{
  "name": "VaniBridge AI",
  "description": "An automated video dubbing tool for rural education using Gemini models for transcription, translation, and speech generation."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppStep {
  UPLOAD = 'UPLOAD',
  PROCESSING = 'PROCESSING',
  RESULT = 'RESULT'
}

export enum TargetLanguage {
  HINDI = 'Hindi',
  MARATHI = 'Marathi',
  TAMIL = 'Tamil',
  TELUGU = 'Telugu'
}

export interface ProcessingState {
  step: AppStep;
  isMockMode: boolean;
  videoFile: File | null;
  videoUrl: string | null;
  transcript: string;
  translatedText: string;
  audioUrl: string | null;
  isProcessing: boolean;
  progress: number; // 0 to 100
  logs: string[];
}

export interface GeminiError {
  message: string;
}

import { GoogleGenAI, Modality } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Helper to convert File to Base64
 */
export const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve({
        inlineData: {
          data: base64String,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Step 1: Transcribe Video Audio (English)
 * Uses gemini-3-flash-preview for fast multimodal understanding
 */
export const transcribeVideo = async (file: File): Promise<string> => {
  const videoPart = await fileToGenerativePart(file);

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        videoPart,
        { text: "Listen to the audio in this video carefully. Transcribe the spoken English words accurately. Return ONLY the transcription text, no other commentary." }
      ]
    }
  });

  return response.text || "";
};

/**
 * Step 2: Translate Text
 * Uses gemini-3-flash-preview for translation
 */
export const translateText = async (text: string, targetLang: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { text: `Translate the following English text to ${targetLang}. Ensure the tone is educational and suitable for rural audiences. Return ONLY the translated text.\n\nText: "${text}"` }
      ]
    }
  });

  return response.text || "";
};

/**
 * Step 3: Generate Speech (TTS)
 * Uses gemini-2.5-flash-preview-tts
 */
export const generateSpeech = async (text: string, targetLang: string): Promise<string> => {
  // Mapping languages to suitable voices (approximations based on available voices)
  // Currently Gemini TTS has specific prebuilt voices. We will use a standard one.
  // Note: Gemini TTS voices are currently limited, mostly English-optimized, but 2.5 handles multi-lingual input reasonably well with standard voices.

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: text }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' }, // 'Kore' is a balanced voice
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

  if (!base64Audio) {
    throw new Error("Failed to generate audio");
  }

  // Convert Base64 to Blob URL
  const binaryString = atob(base64Audio);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  const blob = new Blob([bytes], { type: 'audio/wav' }); // Gemini TTS usually returns WAV/PCM wrapped
  return URL.createObjectURL(blob);
};

// Helper for Audio Context decoding if we needed to play raw PCM, 
// but for simplicity in the UI <audio> tag, we attempt to treat it as a Blob.
// Note: If Gemini returns raw PCM without header, we might need the decodeAudioData flow from the guide.
// For the purpose of the <audio> src, we'll try standard container assumption or fallback to the decode flow if strictly raw.
// However, the guide shows `responseModalities: [Modality.AUDIO]` returns a base64 string.
// Let's implement the robust decode flow for playback if needed, but for "download/src" link, simple Blob is easier.
// *Correction based on guide*: The guide uses AudioContext to decode. 
// For a simple hackathon "Preview", we will use the AudioContext to play it, 
// but to visualize it as a file URL, we might need a WAV header injection if it's raw PCM.
// *Simplification*: We will return the Base64 and let the UI handle playback via AudioContext to be safe.

export const generateSpeechData = async (text: string): Promise<ArrayBuffer> => {
   const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: text }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Puck' },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio data returned");

  const binaryString = atob(base64Audio);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes.buffer;
}

import React from 'react';

