                {state.youtubeId && (
                    <div className="text-xs text-amber-400 bg-amber-900/30 p-2 rounded text-center">
                        Note: For YouTube videos, please click the Play button to start the dubbed audio. You may need to manually play the video if autoplay is blocked.
