               <div className="bg-red-500/10 border border-red-500/50 rounded-2xl p-8 text-center animate-fadeIn">
                  <div className="bg-red-500/20 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                    </svg>
                  </div>
                  <h3 className="text-xl font-bold text-white mb-2">Processing Failed</h3>
                  <p className="text-red-200 mb-6 whitespace-pre-line text-sm">{state.logs[state.logs.length - 1]?.replace("Error: ", "")}</p>

                  <div className="flex gap-4 justify-center">
                    <button 
                      onClick={() => setState(p => ({ ...p, step: AppStep.UPLOAD, statusMessage: "Ready", logs: [], progress: 0 }))}
                      className="px-6 py-2 bg-slate-700 hover:bg-slate-600 rounded-lg text-white font-medium transition-colors"
                    >
                      Back to Upload
                    </button>
                    {!state.isMockMode && state.inputMode === InputMode.YOUTUBE && (
                        <button 
                          onClick={() => setState(p => ({ ...p, isMockMode: true, step: AppStep.UPLOAD, statusMessage: "Ready", logs: [], progress: 0 }))}
                          className="px-6 py-2 bg-blue-600 hover:bg-blue-700 rounded-lg text-white font-medium transition-colors shadow-lg shadow-blue-500/20"
                        >
                          Enable Mock Mode & Retry
