                  <p className="text-slate-400 text-sm leading-relaxed">{state.transcript}</p>
                </div>
                <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 flex-grow">
                  <h3 className="text-blue-300 font-semibold mb-4 border-b border-slate-700 pb-2">Translation ({targetLang})</h3>
                  <p className="text-slate-300 text-sm leading-relaxed font-medium">{state.translatedText}</p>
                </div>
              </div>
            </div>

            <div className="flex gap-4">
               <button 
                onClick={handleReset}
                className="flex-1 py-3 rounded-lg border border-slate-600 hover:bg-slate-800 text-slate-300 transition-colors"
              >
                Process Another Video
              </button>
               {/* Audio Download Button */}
               {state.audioUrl && (
                  <a 
                    href={state.audioUrl} 
                    download={`dubbed_audio_${targetLang}.wav`}
                    className="flex-1 flex items-center justify-center gap-2 py-3 rounded-lg bg-slate-700 hover:bg-slate-600 text-white font-medium transition-colors border border-slate-600"
                  >
                    <DownloadIcon />
                    Download Audio
                  </a>
               )}
               {/* Video Download Button (Simulated) */}
               <button 
                className="flex-1 py-3 rounded-lg bg-blue-600 hover:bg-blue-700 text-white font-medium transition-colors shadow-lg shadow-blue-500/20"
                onClick={() => alert("Full Video Download feature would run FFmpeg in a backend environment to merge audio/video!")}
              >
                Download Video
              </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { TargetLanguage, ProcessingState, AppStep, InputMode } from './types';
import { transcribeVideo, translateText, generateSpeechData, generateGenericTranscript } from './services/geminiService';
import { UploadIcon, PlayIcon, LoadingSpinner, YouTubeIcon, LinkIcon, VolumeIcon, DownloadIcon } from './components/Icon';
import { ProcessingLog } from './components/ProcessingLog';

// Increased limit to approx 2GB to support up to 3600s videos depending on bitrate, though browser memory limits apply for Base64 conversion.
const MAX_FILE_SIZE = 2000 * 1024 * 1024; 

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.HINDI);
  const [state, setState] = useState<ProcessingState>({
    step: AppStep.UPLOAD,
    inputMode: InputMode.FILE,
    isMockMode: true,
    videoFile: null,
    youtubeUrl: '',
    youtubeId: null,
    videoUrl: null,
    transcript: '',
    translatedText: '',
    audioUrl: null,
    isProcessing: false,
    progress: 0,
    logs: [],
    statusMessage: "Ready to process"
  });

  const [audioBuffer, setAudioBuffer] = useState<AudioBuffer | null>(null);
  const [volume, setVolume] = useState<number>(1.0);
  const audioContextRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const iframeRef = useRef<HTMLIFrameElement>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);

  // Initialize AudioContext
  useEffect(() => {
    // We don't force sampleRate here to ensure broader browser compatibility.
    // We will define the content sample rate (24kHz) when creating the buffer.
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();

    // Create GainNode for volume control
    const gainNode = ctx.createGain();
    gainNode.gain.value = 1.0; // Default max volume
    gainNode.connect(ctx.destination);

    audioContextRef.current = ctx;
    gainNodeRef.current = gainNode;

    return () => {
      audioContextRef.current?.close();
    };
  }, []);

  const addLog = (message: string) => {
    setState(prev => ({ ...prev, logs: [...prev.logs, message] }));
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > MAX_FILE_SIZE) {
        alert("File size exceeds the 2GB limit.");
        return;
      }
      const url = URL.createObjectURL(file);
      setState(prev => ({
        ...prev,
        videoFile: file,
        videoUrl: url,
        youtubeId: null,
        logs: [`Loaded video: ${file.name} (${(file.size / 1024 / 1024).toFixed(2)} MB)`]
      }));
    }
  };

  const handleUrlChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setState(prev => ({ ...prev, youtubeUrl: e.target.value }));
  };

  const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newVolume = parseFloat(e.target.value);
    setVolume(newVolume);
    if (gainNodeRef.current) {
      gainNodeRef.current.gain.value = newVolume;
    }
  };

  const createWavUrl = (pcmData: ArrayBuffer): string => {
    const sampleRate = 24000;
    const numChannels = 1;
    const bitsPerSample = 16;

    const header = new ArrayBuffer(44);
    const view = new DataView(header);

    const writeString = (offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) {
        view.setUint8(offset + i, string.charCodeAt(i));
      }
    };

    // RIFF chunk descriptor
    writeString(0, 'RIFF');
    view.setUint32(4, 36 + pcmData.byteLength, true); // File size
    writeString(8, 'WAVE');

    // fmt sub-chunk
    writeString(12, 'fmt ');
    view.setUint32(16, 16, true); // Subchunk1Size (16 for PCM)
    view.setUint16(20, 1, true); // AudioFormat (1 for PCM)
    view.setUint16(22, numChannels, true); // NumChannels
    view.setUint32(24, sampleRate, true); // SampleRate
    view.setUint32(28, sampleRate * numChannels * (bitsPerSample / 8), true); // ByteRate
    view.setUint16(32, numChannels * (bitsPerSample / 8), true); // BlockAlign
    view.setUint16(34, bitsPerSample, true); // BitsPerSample

    // data sub-chunk
    writeString(36, 'data');
    view.setUint32(40, pcmData.byteLength, true);

    const blob = new Blob([header, pcmData], { type: 'audio/wav' });
    return URL.createObjectURL(blob);
  };

  const decodeAudio = async (arrayBuffer: ArrayBuffer) => {
    if (!audioContextRef.current) return;

    // Gemini TTS returns raw PCM 16-bit 24kHz Mono audio.
    // Browser's decodeAudioData expects a file header (like WAV), so we must decode manually.
    try {
      const pcmData = new Int16Array(arrayBuffer);
      const numChannels = 1;
      const sampleRate = 24000;

      const buffer = audioContextRef.current.createBuffer(numChannels, pcmData.length, sampleRate);
      const channelData = buffer.getChannelData(0);

      for (let i = 0; i < pcmData.length; i++) {
        // Normalize 16-bit integer to float range [-1.0, 1.0]
        channelData[i] = pcmData[i] / 32768.0;
      }

      setAudioBuffer(buffer);
    } catch (e) {
      console.error("PCM Decode Error:", e);
      addLog("Error: Failed to decode audio data.");
    }
  };

  const getYouTubeId = (url: string): string | null => {
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? match[2] : null;
  };

  const fetchVideoFromUrl = async (url: string, onProgress: (percent: number) => void): Promise<File> => {
    // Removed try/catch wrapper to let errors propagate to the caller for specific handling
    const response = await fetch(url);
    if (!response.ok) throw new Error(`Network response was not ok (${response.status})`);

    const contentLength = response.headers.get('content-length');
    const total = contentLength ? parseInt(contentLength, 10) : 0;
    let loaded = 0;

    const reader = response.body?.getReader();
    const chunks: Uint8Array[] = [];

    if (!reader) {
      const blob = await response.blob();
      onProgress(100);
      return new File([blob], "downloaded_video.mp4", { type: blob.type || 'video/mp4' });
    }

    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      if (value) {
        chunks.push(value);
        loaded += value.length;
        if (total > 0) {
          onProgress((loaded / total) * 100);
        }
      }
    }

    onProgress(100);

    const blob = new Blob(chunks, { type: response.headers.get('content-type') || 'video/mp4' });
    return new File([blob], "downloaded_video.mp4", { type: blob.type });
  };

  const startProcessing = async () => {
    let processingFile = state.videoFile;
    let extractedYoutubeId = null;

    setState(prev => ({ 
      ...prev, 
      step: AppStep.PROCESSING, 
      isProcessing: true, 
      progress: 0, 
      statusMessage: "Initializing VaniBridge Pipeline..." 
    }));
    addLog("Initializing VaniBridge Pipeline...");

    try {
      // Step 0: Handle YouTube/URL Download
      if (state.inputMode === InputMode.YOUTUBE) {
        const url = state.youtubeUrl.trim();
        if (!url) {
           throw new Error("Please enter a valid URL.");
        }

        addLog(`Analyzing URL: ${url}`);

        extractedYoutubeId = getYouTubeId(url);

        // Update state with ID immediately
        if (extractedYoutubeId) {
            addLog(`Detected YouTube Video ID: ${extractedYoutubeId}`);
        } else {
            // Check if it's a YouTube URL but ID wasn't extracted
            if (url.toLowerCase().includes('youtube.com') || url.toLowerCase().includes('youtu.be')) {
               addLog("Warning: Looks like a YouTube URL but video ID was not found.");
            } else {
               addLog(`Analyzing custom video URL...`);
            }
        }

        setState(prev => ({ ...prev, youtubeId: extractedYoutubeId }));

        if (state.isMockMode && extractedYoutubeId) {
           // MOCK PATH for YouTube in Demo (since browser can't CORS fetch YT)
           addLog("YouTube Detected + Mock Mode: Initiating simulation...");

           // Simulated download progress
           for (let i = 0; i <= 100; i += 5) {
             await new Promise(r => setTimeout(r, 50));
             setState(prev => ({ 
               ...prev, 
               progress: Math.floor(i * 0.3), // 0-30% global progress
               statusMessage: `Analyzing YouTube metadata (Simulated): ${i}%` 
             }));
           }

           addLog("Video Stream Analyzed (Simulated)");

           // We need a dummy file to keep the pipeline happy if we are mocking
           processingFile = new File(["dummy video content"], "mock_video.mp4", { type: "video/mp4" });
        } else {
           // Try Real Fetch (Direct MP4 or User insists on processing URL)
           addLog("Attempting direct video download...");
           try {
             processingFile = await fetchVideoFromUrl(url, (percent) => {
               setState(prev => ({ 
                 ...prev, 
                 progress: Math.floor(percent * 0.3), // 0-30% global progress
                 statusMessage: `Downloading video: ${Math.round(percent)}%`
               }));
             });
             const blobUrl = URL.createObjectURL(processingFile);
             setState(prev => ({ ...prev, videoUrl: blobUrl, videoFile: processingFile, youtubeId: null })); // Reset youtubeId if real file
             addLog(`Download Complete: ${(processingFile.size / 1024 / 1024).toFixed(2)} MB`);
           } catch (e) {
              if (state.isMockMode) {
                 addLog("Download failed (CORS/Access). Falling back to Mock Video simulation.");
                 processingFile = new File(["mock"], "mock.mp4", { type: "video/mp4" });
              } else {
                 // Enhanced Error Handling
                 console.error("Download Error:", e);
                 if (extractedYoutubeId) {
                   throw new Error("Cannot download YouTube videos directly in browser mode. \nReason: YouTube does not allow direct cross-origin (CORS) downloads.\n\nSolution: Please enable 'Mock Mode' to test the app flow, or use a direct link to an MP4 file.");
                 } else if (url.toLowerCase().includes('youtube.com') || url.toLowerCase().includes('youtu.be')) {
                   throw new Error("Invalid or restricted YouTube URL. Ensure the URL is correct and the video is public. Try 'Mock Mode' for testing.");
                 } else {
                   throw new Error(`Failed to access video URL. \nReason: ${(e as Error).message}. \n\nTip: Ensure the link is a direct download (e.g., ends in .mp4) and the server allows CORS.`);
                 }
              }
           }
        }
      }

      if (!processingFile) {
        throw new Error("No video file loaded.");
      }

      // Step 1: Transcription
      setState(prev => ({ ...prev, progress: 35, statusMessage: "Transcribing audio..." }));
      addLog("Extracting audio & Transcribing (Gemini 3 Flash)...");
      let transcript = "";

      // If we are in Mock Mode with a dummy file, use DYNAMIC mock transcript
      if (state.isMockMode && processingFile.size < 100) {
         await new Promise(resolve => setTimeout(resolve, 1000));
         addLog("(Mock) Generating dynamic educational transcript using Gemini...");
         transcript = await generateGenericTranscript();
         addLog("(Mock) Transcript generated successfully.");
      } else {
         transcript = await transcribeVideo(processingFile);
      }

      setState(prev => ({ ...prev, transcript, progress: 60, statusMessage: "Translating content..." }));
      addLog(`Transcription Complete: "${transcript.substring(0, 30)}..."`);

      // Step 2: Translation
      addLog(`Translating to ${targetLang} (Gemini 3 Flash)...`);
      const translated = await translateText(transcript, targetLang);
      setState(prev => ({ ...prev, translatedText: translated, progress: 80, statusMessage: "Generating speech..." }));
      addLog(`Translation Complete: "${translated.substring(0, 30)}..."`);

      // Step 3: TTS
      addLog("Generating Neural Speech (Gemini 2.5 TTS)...");
      const audioData = await generateSpeechData(translated);
      const wavUrl = createWavUrl(audioData);
      await decodeAudio(audioData);

      setState(prev => ({ ...prev, progress: 95, statusMessage: "Synchronizing...", audioUrl: wavUrl }));
      addLog("Audio Generation Complete.");

      // Step 4: Lip Sync Mock Logic
      addLog(state.isMockMode ? "Mock Mode: Active. Syncing audio playback..." : "Running Wav2Lip (Simulated)...");

      // Simulate slight delay for "heavy processing" feel
      await new Promise(resolve => setTimeout(resolve, 1500));

      addLog("Pipeline Finalized. Ready to play.");
      setState(prev => ({ 
        ...prev, 
        step: AppStep.RESULT, 
        isProcessing: false, 
        progress: 100, 
        statusMessage: "Done" 
      }));

    } catch (error) {
      console.error(error);
      const msg = error instanceof Error ? error.message : "Unknown error";
      // Only add log if it wasn't already logged
      addLog(`Error: ${msg}`);
      setState(prev => ({ ...prev, isProcessing: false, statusMessage: "Process Failed" }));
    }
  };

  const handlePlayResult = () => {
    // Resume AudioContext just in case it was suspended (browser policy)
    if (audioContextRef.current && audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }

    // Play Local Video
    if (videoRef.current) {
       videoRef.current.currentTime = 0;
       videoRef.current.play();
    }

    // Play YouTube Video via PostMessage (synchronize with audio)
    if (state.youtubeId && iframeRef.current && iframeRef.current.contentWindow) {
        iframeRef.current.contentWindow.postMessage('{"event":"command","func":"seekTo","args":[0, true]}', '*');
        iframeRef.current.contentWindow.postMessage('{"event":"command","func":"playVideo","args":""}', '*');
    }

    // Play Dubbed Audio
    if (audioBuffer && audioContextRef.current) {
      if (sourceNodeRef.current) {
        sourceNodeRef.current.stop();
      }
      const source = audioContextRef.current.createBufferSource();
      source.buffer = audioBuffer;

      // Connect to gain node if available, otherwise destination
      if (gainNodeRef.current) {
        source.connect(gainNodeRef.current);
      } else {
        source.connect(audioContextRef.current.destination);
      }

      source.start();
      sourceNodeRef.current = source;
    }
  };

  const handleReset = () => {
    if (state.audioUrl) {
      URL.revokeObjectURL(state.audioUrl);
    }
    setState({
      step: AppStep.UPLOAD,
      inputMode: InputMode.FILE,
      isMockMode: true,
      videoFile: null,
      youtubeUrl: '',
      youtubeId: null,
      videoUrl: null,
      transcript: '',
      translatedText: '',
      audioUrl: null,
      isProcessing: false,
      progress: 0,
      logs: [],
      statusMessage: "Ready"
    });
    setAudioBuffer(null);
    setVolume(1.0);
    if (gainNodeRef.current) {
      gainNodeRef.current.gain.value = 1.0;
    }
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-50 flex flex-col items-center">
      {/* Header */}
      <header className="w-full bg-slate-800 border-b border-slate-700 p-4 shadow-lg sticky top-0 z-50">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-gradient-to-tr from-blue-500 to-purple-600 p-2 rounded-lg">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
              </svg>
            </div>
            <div>
              <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-purple-400">
                VaniBridge AI
              </h1>
              <p className="text-xs text-slate-400">Bridging Language Barriers in Education</p>
            </div>
          </div>
          <div className="text-xs text-slate-500 border border-slate-700 rounded px-2 py-1">
            GSA Tech Summit 2026
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="w-full max-w-4xl p-6 flex-grow flex flex-col gap-8">

        {/* Step Indicator */}
        <div className="flex justify-between items-center px-8 relative">
          <div className="absolute top-1/2 left-0 w-full h-1 bg-slate-800 -z-10"></div>
          {[AppStep.UPLOAD, AppStep.PROCESSING, AppStep.RESULT].map((s, idx) => (
            <div key={s} className={`flex flex-col items-center bg-slate-900 px-2`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm transition-colors ${
                state.step === s ? 'bg-blue-500 text-white' : 
                (Object.values(AppStep).indexOf(state.step) > idx ? 'bg-green-500 text-white' : 'bg-slate-700 text-slate-400')
              }`}>
                {idx + 1}
              </div>
              <span className="text-xs mt-2 text-slate-400 font-medium">{s}</span>
            </div>
          ))}
        </div>

        {/* UPLOAD VIEW */}
        {state.step === AppStep.UPLOAD && (
          <div className="flex flex-col gap-6 animate-fadeIn">

            {/* Input Mode Toggles */}
            <div className="flex bg-slate-800 p-1 rounded-xl border border-slate-700 self-center">
               <button 
                  onClick={() => setState(p => ({ ...p, inputMode: InputMode.FILE, videoFile: null, videoUrl: null, youtubeId: null }))}
                  className={`px-6 py-2 rounded-lg text-sm font-medium transition-all ${state.inputMode === InputMode.FILE ? 'bg-slate-600 text-white shadow-sm' : 'text-slate-400 hover:text-white'}`}
               >
                 File Upload
               </button>
               <button 
                  onClick={() => setState(p => ({ ...p, inputMode: InputMode.YOUTUBE, videoFile: null, videoUrl: null, youtubeId: null }))}
                  className={`px-6 py-2 rounded-lg text-sm font-medium transition-all ${state.inputMode === InputMode.YOUTUBE ? 'bg-red-600 text-white shadow-sm' : 'text-slate-400 hover:text-white'}`}
               >
                 YouTube / URL
               </button>
            </div>

            {state.inputMode === InputMode.FILE ? (
              <div className="bg-slate-800 rounded-2xl border-2 border-dashed border-slate-600 p-12 flex flex-col items-center justify-center gap-4 hover:border-blue-500 transition-colors group relative h-72">
                <input 
                  type="file" 
                  accept="video/mp4" 
                  onChange={handleFileUpload}
                  className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                />
                <UploadIcon />
                <div className="text-center">
                  <p className="text-lg font-medium text-slate-200">
                    {state.videoFile ? state.videoFile.name : "Drop your educational video here"}
                  </p>
                  <p className="text-sm text-slate-500 mt-1">MP4 format, Max 3600s</p>
                </div>
                {state.videoFile && (
                  <div className="mt-4">
                     <span className="bg-green-500/20 text-green-300 px-3 py-1 rounded-full text-sm">
                      Ready to Process
                     </span>
                  </div>
                )}
              </div>
            ) : (
              <div className="bg-slate-800 rounded-2xl border border-slate-700 p-8 flex flex-col items-center justify-center gap-6 h-80 shadow-inner bg-gradient-to-b from-slate-800 to-slate-900">
                 <div className="flex flex-col items-center gap-2">
                    <div className="p-3 bg-red-500/10 rounded-full">
                       <YouTubeIcon />
                    </div>
                    <h3 className="text-white font-semibold text-xl">Import Video from Web</h3>
                    <p className="text-slate-400 text-sm max-w-xs text-center">
                      Paste a URL from YouTube or a direct link to an MP4 file to start the dubbing process.
                    </p>
                 </div>

                 <div className="w-full max-w-xl">
                   <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 ml-1">Video URL</label>
                   <div className="relative group">
                      <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-slate-400 group-focus-within:text-blue-400 transition-colors">
                        <LinkIcon />
                      </div>
                      <input 
                        type="text" 
                        value={state.youtubeUrl}
                        onChange={handleUrlChange}
                        placeholder="https://www.youtube.com/watch?v=..." 
                        className="w-full bg-slate-950 border border-slate-600 rounded-xl py-4 pl-12 pr-4 text-lg text-white focus:border-blue-500 focus:ring-4 focus:ring-blue-500/20 outline-none placeholder-slate-600 transition-all shadow-lg"
                        autoFocus
                      />
                   </div>

                   <div className="mt-4 bg-slate-950/50 rounded-lg p-3 border border-slate-800">
                     <div className="flex items-center gap-2 text-xs text-slate-400 mb-1">
                       <span className="font-semibold text-slate-300">Try with this example:</span>
                     </div>
                     <div 
                       className="flex items-center justify-between gap-2 text-xs font-mono text-blue-300 bg-blue-500/5 px-2 py-1.5 rounded cursor-pointer hover:bg-blue-500/10 transition-colors border border-blue-500/10"
                       onClick={() => setState(p => ({ ...p, youtubeUrl: "https://www.youtube.com/watch?v=dQw4w9WgXcQ" }))}
                       title="Click to use example"
                     >
                       <span className="truncate">https://www.youtube.com/watch?v=dQw4w9WgXcQ</span>
                       <span className="text-[10px] bg-blue-500/20 px-1.5 py-0.5 rounded text-blue-200">Click to fill</span>
                     </div>
                   </div>
                 </div>
              </div>
            )}

            <div className="bg-slate-800 p-6 rounded-xl border border-slate-700">
              <h2 className="text-lg font-semibold mb-4">Configuration</h2>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm text-slate-400 mb-2">Target Language</label>
                  <select 
                    value={targetLang} 
                    onChange={(e) => setTargetLang(e.target.value as TargetLanguage)}
                    className="w-full bg-slate-700 border border-slate-600 rounded-lg p-3 text-white focus:ring-2 focus:ring-blue-500 outline-none"
                  >
                    {Object.values(TargetLanguage).map(lang => (
                      <option key={lang} value={lang}>{lang}</option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className="block text-sm text-slate-400 mb-2">Processing Mode</label>
                  <div className="flex items-center gap-3 bg-slate-700 p-3 rounded-lg border border-slate-600">
                    <div 
                      className={`w-10 h-6 rounded-full p-1 cursor-pointer transition-colors ${state.isMockMode ? 'bg-blue-500' : 'bg-slate-500'}`}
                      onClick={() => setState(p => ({...p, isMockMode: !p.isMockMode}))}
                    >
                      <div className={`w-4 h-4 bg-white rounded-full shadow-md transform transition-transform ${state.isMockMode ? 'translate-x-4' : ''}`}></div>
                    </div>
                    <span className="text-sm text-slate-200">
                      Mock Lip-Sync (Laptop Safe)
                    </span>
                  </div>
                  <p className="text-xs text-slate-500 mt-2">
                    Enable Mock Mode to skip heavy Wav2Lip processing (Demo).
                  </p>
                </div>
              </div>
            </div>

            <button 
              onClick={startProcessing}
              disabled={state.inputMode === InputMode.FILE ? !state.videoFile : !state.youtubeUrl}
              className={`w-full py-4 rounded-xl font-bold text-lg transition-all transform active:scale-95 ${
                (state.inputMode === InputMode.FILE ? state.videoFile : state.youtubeUrl)
                ? 'bg-gradient-to-r from-blue-600 to-purple-600 hover:shadow-blue-500/25 shadow-lg text-white' 
                : 'bg-slate-700 text-slate-500 cursor-not-allowed'
              }`}
            >
              Start Dubbing Process
            </button>
          </div>
        )}

        {/* PROCESSING VIEW */}
        {state.step === AppStep.PROCESSING && (
          <div className="flex flex-col gap-6 animate-fadeIn">
            {/* Error State Check */}
            {!state.isProcessing && state.statusMessage === "Process Failed" ? (
               <div className="bg-red-500/10 border border-red-500/50 rounded-2xl p-8 text-center animate-fadeIn">
                  <div className="bg-red-500/20 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                    </svg>
                  </div>
                  <h3 className="text-xl font-bold text-white mb-2">Processing Failed</h3>
                  <p className="text-red-200 mb-6 whitespace-pre-line text-sm">{state.logs[state.logs.length - 1]?.replace("Error: ", "")}</p>

                  <div className="flex gap-4 justify-center">
                    <button 
                      onClick={() => setState(p => ({ ...p, step: AppStep.UPLOAD, statusMessage: "Ready", logs: [], progress: 0 }))}
                      className="px-6 py-2 bg-slate-700 hover:bg-slate-600 rounded-lg text-white font-medium transition-colors"
                    >
                      Back to Upload
                    </button>
                    {!state.isMockMode && state.inputMode === InputMode.YOUTUBE && (
                        <button 
                          onClick={() => setState(p => ({ ...p, isMockMode: true, step: AppStep.UPLOAD, statusMessage: "Ready", logs: [], progress: 0 }))}
                          className="px-6 py-2 bg-blue-600 hover:bg-blue-700 rounded-lg text-white font-medium transition-colors shadow-lg shadow-blue-500/20"
                        >
                          Enable Mock Mode & Retry
                        </button>
                    )}
                  </div>
               </div>
            ) : (
               <div className="bg-slate-800 p-8 rounded-2xl border border-slate-700 text-center">
                  <div className="w-20 h-20 mx-auto mb-6 relative">
                     <div className="absolute inset-0 border-4 border-slate-700 rounded-full"></div>
                     <div 
                        className="absolute inset-0 border-4 border-blue-500 rounded-full transition-all duration-300 ease-out"
                        style={{ clipPath: `inset(0 0 ${100 - state.progress}% 0)` }}
                     ></div>
                     <div className="absolute inset-0 flex items-center justify-center font-bold text-xl">
                       {state.progress}%
                     </div>
                  </div>
                  <h2 className="text-2xl font-bold mb-2">Processing Video</h2>
                  <p className="text-slate-400">{state.statusMessage}</p>
               </div>
            )}

            <ProcessingLog logs={state.logs} isProcessing={state.isProcessing} />

            {state.translatedText && (
               <div className="bg-slate-800/50 p-4 rounded-lg border border-slate-700">
                 <h4 className="text-xs uppercase text-slate-500 mb-2">Translation Preview</h4>
                 <p className="text-lg font-serif italic text-blue-200">"{state.translatedText}"</p>
               </div>
            )}
          </div>
        )}

        {/* RESULT VIEW */}
        {state.step === AppStep.RESULT && (
          <div className="flex flex-col gap-8 animate-fadeIn">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {/* Video Player Column */}
              <div className="flex flex-col gap-4">
                <div className="bg-black rounded-2xl overflow-hidden shadow-2xl relative aspect-video group">
                  {state.youtubeId ? (
                    // YouTube Iframe Embed
                    <iframe
                      ref={iframeRef}
                      width="100%"
                      height="100%"
                      src={`https://www.youtube.com/embed/${state.youtubeId}?enablejsapi=1&controls=0&mute=1&autoplay=0`}
                      title="YouTube video player"
                      frameBorder="0"
                      allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                      className="w-full h-full object-cover"
                    ></iframe>
                  ) : state.videoUrl ? (
                    // Direct Video File
                    <video 
                      ref={videoRef}
                      src={state.videoUrl} 
                      className="w-full h-full object-cover opacity-80"
                      playsInline
                      muted // Important: We play the generated audio instead
                    />
                  ) : (
                    <div className="w-full h-full flex items-center justify-center bg-slate-800 text-slate-500">
                      <p>Video Preview Unavailable (Simulated)</p>
                    </div>
                  )}

                  {/* Play Button Overlay - Only for Local Files or Manual Sync on YT */}
                  <div className="absolute inset-0 flex items-center justify-center bg-black/30 group-hover:bg-black/10 transition-colors pointer-events-none">
                    <button 
                      onClick={handlePlayResult}
                      className="bg-white/10 backdrop-blur-md hover:bg-white/20 p-4 rounded-full border border-white/30 transition-all transform hover:scale-110 pointer-events-auto"
                    >
                      <PlayIcon />
                    </button>
                  </div>

                  <div className="absolute bottom-4 left-4 bg-black/60 px-3 py-1 rounded text-xs text-white pointer-events-none">
                    Dubbed: {targetLang}
                  </div>
                </div>

                {/* Volume Control */}
                <div className="flex items-center gap-3 bg-slate-800 p-3 rounded-xl border border-slate-700">
                   <div className="text-slate-400">
                     <VolumeIcon />
                   </div>
                   <input 
                     type="range" 
                     min="0" 
                     max="1" 
                     step="0.01" 
                     value={volume} 
                     onChange={handleVolumeChange}
                     className="w-full h-2 bg-slate-600 rounded-lg appearance-none cursor-pointer accent-blue-500"
                   />
                </div>

                {state.youtubeId && (
                    <div className="text-xs text-slate-400 bg-slate-800 p-2 rounded text-center">
                        <span className="text-blue-300 font-semibold">Tip:</span> Use the central Play button to start both the video and dubbed audio.
                    </div>
                )}
              </div>

              {/* Details Pane */}
              <div className="flex flex-col gap-4">
                <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 flex-grow">
                  <h3 className="text-slate-300 font-semibold mb-4 border-b border-slate-700 pb-2">Transcription (English)</h3>
                  <p className="text-slate-400 text-sm leading-relaxed">{state.transcript}</p>
                </div>
                <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 flex-grow">
                  <h3 className="text-blue-300 font-semibold mb-4 border-b border-slate-700 pb-2">Translation ({targetLang})</h3>
                  <p className="text-slate-300 text-sm leading-relaxed font-medium">{state.translatedText}</p>
                </div>
              </div>
            </div>

            <div className="flex gap-4">
               <button 
                onClick={handleReset}
                className="flex-1 py-3 rounded-lg border border-slate-600 hover:bg-slate-800 text-slate-300 transition-colors"
              >
                Process Another Video
              </button>
               {/* Audio Download Button */}
               {state.audioUrl && (
                  <a 
                    href={state.audioUrl} 
                    download={`dubbed_audio_${targetLang}.wav`}
                    className="flex-1 flex items-center justify-center gap-2 py-3 rounded-lg bg-slate-700 hover:bg-slate-600 text-white font-medium transition-colors border border-slate-600"
                  >
                    <DownloadIcon />
                    Download Audio
                  </a>
               )}
               {/* Video Download Button (Simulated) */}
               <button 
                className="flex-1 py-3 rounded-lg bg-blue-600 hover:bg-blue-700 text-white font-medium transition-colors shadow-lg shadow-blue-500/20"
                onClick={() => alert("Full Video Download feature would run FFmpeg in a backend environment to merge audio/video!")}
              >
                Download Video
              </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { TargetLanguage, ProcessingState, AppStep, InputMode } from './types';
import { transcribeVideo, translateText, generateSpeechData, generateGenericTranscript } from './services/geminiService';
import { UploadIcon, PlayIcon, LoadingSpinner, YouTubeIcon, LinkIcon, VolumeIcon, DownloadIcon } from './components/Icon';
import { ProcessingLog } from './components/ProcessingLog';

// Increased limit to approx 2GB to support up to 3600s videos depending on bitrate, though browser memory limits apply for Base64 conversion.
const MAX_FILE_SIZE = 2000 * 1024 * 1024; 

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.HINDI);
  const [state, setState] = useState<ProcessingState>({
    step: AppStep.UPLOAD,
    inputMode: InputMode.FILE,
    isMockMode: true,
    videoFile: null,
    youtubeUrl: '',
    youtubeId: null,
    videoUrl: null,
    transcript: '',
    translatedText: '',
    audioUrl: null,
    isProcessing: false,
    progress: 0,
    logs: [],
    statusMessage: "Ready to process"
  });

  const [audioBuffer, setAudioBuffer] = useState<AudioBuffer | null>(null);
  const [volume, setVolume] = useState<number>(1.0);
  const audioContextRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const iframeRef = useRef<HTMLIFrameElement>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);

  // Initialize AudioContext
  useEffect(() => {
    // We don't force sampleRate here to ensure broader browser compatibility.
    // We will define the content sample rate (24kHz) when creating the buffer.
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();

    // Create GainNode for volume control
    const gainNode = ctx.createGain();
    gainNode.gain.value = 1.0; // Default max volume
    gainNode.connect(ctx.destination);

    audioContextRef.current = ctx;
    gainNodeRef.current = gainNode;

    return () => {
      audioContextRef.current?.close();
    };
  }, []);

  const addLog = (message: string) => {
    setState(prev => ({ ...prev, logs: [...prev.logs, message] }));
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > MAX_FILE_SIZE) {
        alert("File size exceeds the 2GB limit.");
        return;
      }
      const url = URL.createObjectURL(file);
      setState(prev => ({
        ...prev,
        videoFile: file,
        videoUrl: url,
        youtubeId: null,
        logs: [`Loaded video: ${file.name} (${(file.size / 1024 / 1024).toFixed(2)} MB)`]
      }));
    }
  };

  const handleUrlChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setState(prev => ({ ...prev, youtubeUrl: e.target.value }));
  };

  const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newVolume = parseFloat(e.target.value);
    setVolume(newVolume);
    if (gainNodeRef.current) {
      gainNodeRef.current.gain.value = newVolume;
    }
  };

  const createWavUrl = (pcmData: ArrayBuffer): string => {
    const sampleRate = 24000;
    const numChannels = 1;
    const bitsPerSample = 16;

    const header = new ArrayBuffer(44);
    const view = new DataView(header);

    const writeString = (offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) {
        view.setUint8(offset + i, string.charCodeAt(i));
      }
    };

    // RIFF chunk descriptor
    writeString(0, 'RIFF');
    view.setUint32(4, 36 + pcmData.byteLength, true); // File size
    writeString(8, 'WAVE');

    // fmt sub-chunk
    writeString(12, 'fmt ');
    view.setUint32(16, 16, true); // Subchunk1Size (16 for PCM)
    view.setUint16(20, 1, true); // AudioFormat (1 for PCM)
    view.setUint16(22, numChannels, true); // NumChannels
    view.setUint32(24, sampleRate, true); // SampleRate
    view.setUint32(28, sampleRate * numChannels * (bitsPerSample / 8), true); // ByteRate
    view.setUint16(32, numChannels * (bitsPerSample / 8), true); // BlockAlign
    view.setUint16(34, bitsPerSample, true); // BitsPerSample

    // data sub-chunk
    writeString(36, 'data');
    view.setUint32(40, pcmData.byteLength, true);

    const blob = new Blob([header, pcmData], { type: 'audio/wav' });
    return URL.createObjectURL(blob);
  };

  const decodeAudio = async (arrayBuffer: ArrayBuffer) => {
    if (!audioContextRef.current) return;

    // Gemini TTS returns raw PCM 16-bit 24kHz Mono audio.
    // Browser's decodeAudioData expects a file header (like WAV), so we must decode manually.
    try {
      const pcmData = new Int16Array(arrayBuffer);
      const numChannels = 1;
      const sampleRate = 24000;

      const buffer = audioContextRef.current.createBuffer(numChannels, pcmData.length, sampleRate);
      const channelData = buffer.getChannelData(0);

      for (let i = 0; i < pcmData.length; i++) {
        // Normalize 16-bit integer to float range [-1.0, 1.0]
        channelData[i] = pcmData[i] / 32768.0;
      }

      setAudioBuffer(buffer);
    } catch (e) {
      console.error("PCM Decode Error:", e);
      addLog("Error: Failed to decode audio data.");
    }
  };

  const getYouTubeId = (url: string): string | null => {
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? match[2] : null;
  };

  const fetchVideoFromUrl = async (url: string, onProgress: (percent: number) => void): Promise<File> => {
    // Removed try/catch wrapper to let errors propagate to the caller for specific handling
    const response = await fetch(url);
    if (!response.ok) throw new Error(`Network response was not ok (${response.status})`);

    const contentLength = response.headers.get('content-length');
    const total = contentLength ? parseInt(contentLength, 10) : 0;
    let loaded = 0;

    const reader = response.body?.getReader();
    const chunks: Uint8Array[] = [];

    if (!reader) {
      const blob = await response.blob();
      onProgress(100);
      return new File([blob], "downloaded_video.mp4", { type: blob.type || 'video/mp4' });
    }

    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      if (value) {
        chunks.push(value);
        loaded += value.length;
        if (total > 0) {
          onProgress((loaded / total) * 100);
        }
      }
    }

    onProgress(100);

    const blob = new Blob(chunks, { type: response.headers.get('content-type') || 'video/mp4' });
    return new File([blob], "downloaded_video.mp4", { type: blob.type });
  };

  const startProcessing = async () => {
    let processingFile = state.videoFile;
    let extractedYoutubeId = null;

    setState(prev => ({ 
      ...prev, 
      step: AppStep.PROCESSING, 
      isProcessing: true, 
      progress: 0, 
      statusMessage: "Initializing VaniBridge Pipeline..." 
    }));
    addLog("Initializing VaniBridge Pipeline...");

    try {
      // Step 0: Handle YouTube/URL Download
      if (state.inputMode === InputMode.YOUTUBE) {
        const url = state.youtubeUrl.trim();
        if (!url) {
           throw new Error("Please enter a valid URL.");
        }

        addLog(`Analyzing URL: ${url}`);

        extractedYoutubeId = getYouTubeId(url);

        // Update state with ID immediately
        if (extractedYoutubeId) {
            addLog(`Detected YouTube Video ID: ${extractedYoutubeId}`);
        } else {
            // Check if it's a YouTube URL but ID wasn't extracted
            if (url.toLowerCase().includes('youtube.com') || url.toLowerCase().includes('youtu.be')) {
               addLog("Warning: Looks like a YouTube URL but video ID was not found.");
            } else {
               addLog(`Analyzing custom video URL...`);
            }
        }

        setState(prev => ({ ...prev, youtubeId: extractedYoutubeId }));

        if (state.isMockMode && extractedYoutubeId) {
           // MOCK PATH for YouTube in Demo (since browser can't CORS fetch YT)
           addLog("YouTube Detected + Mock Mode: Initiating simulation...");

           // Simulated download progress
           for (let i = 0; i <= 100; i += 5) {
             await new Promise(r => setTimeout(r, 50));
             setState(prev => ({ 
               ...prev, 
               progress: Math.floor(i * 0.3), // 0-30% global progress
               statusMessage: `Analyzing YouTube metadata (Simulated): ${i}%` 
             }));
           }

           addLog("Video Stream Analyzed (Simulated)");

           // We need a dummy file to keep the pipeline happy if we are mocking
           processingFile = new File(["dummy video content"], "mock_video.mp4", { type: "video/mp4" });
        } else {
           // Try Real Fetch (Direct MP4 or User insists on processing URL)
           addLog("Attempting direct video download...");
           try {
             processingFile = await fetchVideoFromUrl(url, (percent) => {
               setState(prev => ({ 
                 ...prev, 
                 progress: Math.floor(percent * 0.3), // 0-30% global progress
                 statusMessage: `Downloading video: ${Math.round(percent)}%`
               }));
             });
             const blobUrl = URL.createObjectURL(processingFile);
             setState(prev => ({ ...prev, videoUrl: blobUrl, videoFile: processingFile, youtubeId: null })); // Reset youtubeId if real file
             addLog(`Download Complete: ${(processingFile.size / 1024 / 1024).toFixed(2)} MB`);
           } catch (e) {
              if (state.isMockMode) {
                 addLog("Download failed (CORS/Access). Falling back to Mock Video simulation.");
                 processingFile = new File(["mock"], "mock.mp4", { type: "video/mp4" });
              } else {
                 // Enhanced Error Handling
                 console.error("Download Error:", e);
                 if (extractedYoutubeId) {
                   throw new Error("Cannot download YouTube videos directly in browser mode. \nReason: YouTube does not allow direct cross-origin (CORS) downloads.\n\nSolution: Please enable 'Mock Mode' to test the app flow, or use a direct link to an MP4 file.");
                 } else if (url.toLowerCase().includes('youtube.com') || url.toLowerCase().includes('youtu.be')) {
                   throw new Error("Invalid or restricted YouTube URL. Ensure the URL is correct and the video is public. Try 'Mock Mode' for testing.");
                 } else {
                   throw new Error(`Failed to access video URL. \nReason: ${(e as Error).message}. \n\nTip: Ensure the link is a direct download (e.g., ends in .mp4) and the server allows CORS.`);
                 }
              }
           }
        }
      }

      if (!processingFile) {
        throw new Error("No video file loaded.");
      }

      // Step 1: Transcription
      setState(prev => ({ ...prev, progress: 35, statusMessage: "Transcribing audio..." }));
      addLog("Extracting audio & Transcribing (Gemini 3 Flash)...");
      let transcript = "";

      // If we are in Mock Mode with a dummy file, use DYNAMIC mock transcript
      if (state.isMockMode && processingFile.size < 100) {
         await new Promise(resolve => setTimeout(resolve, 1000));
         addLog("(Mock) Generating dynamic educational transcript using Gemini...");
         transcript = await generateGenericTranscript();
         addLog("(Mock) Transcript generated successfully.");
      } else {
         transcript = await transcribeVideo(processingFile);
      }

      setState(prev => ({ ...prev, transcript, progress: 60, statusMessage: "Translating content..." }));
      addLog(`Transcription Complete: "${transcript.substring(0, 30)}..."`);

      // Step 2: Translation
      addLog(`Translating to ${targetLang} (Gemini 3 Flash)...`);
      const translated = await translateText(transcript, targetLang);
      setState(prev => ({ ...prev, translatedText: translated, progress: 80, statusMessage: "Generating speech..." }));
      addLog(`Translation Complete: "${translated.substring(0, 30)}..."`);

      // Step 3: TTS
      addLog("Generating Neural Speech (Gemini 2.5 TTS)...");
      const audioData = await generateSpeechData(translated);
      const wavUrl = createWavUrl(audioData);
      await decodeAudio(audioData);

      setState(prev => ({ ...prev, progress: 95, statusMessage: "Synchronizing...", audioUrl: wavUrl }));
      addLog("Audio Generation Complete.");

      // Step 4: Lip Sync Mock Logic
      addLog(state.isMockMode ? "Mock Mode: Active. Syncing audio playback..." : "Running Wav2Lip (Simulated)...");

      // Simulate slight delay for "heavy processing" feel
      await new Promise(resolve => setTimeout(resolve, 1500));

      addLog("Pipeline Finalized. Ready to play.");
      setState(prev => ({ 
        ...prev, 
        step: AppStep.RESULT, 
        isProcessing: false, 
        progress: 100, 
        statusMessage: "Done" 
      }));

    } catch (error) {
      console.error(error);
      const msg = error instanceof Error ? error.message : "Unknown error";
      // Only add log if it wasn't already logged
      addLog(`Error: ${msg}`);
      setState(prev => ({ ...prev, isProcessing: false, statusMessage: "Process Failed" }));
    }
  };

  const handlePlayResult = () => {
    // Resume AudioContext just in case it was suspended (browser policy)
    if (audioContextRef.current && audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }

    // Play Local Video
    if (videoRef.current) {
       videoRef.current.currentTime = 0;
       videoRef.current.play();
    }

    // Play YouTube Video via PostMessage (synchronize with audio)
    if (state.youtubeId && iframeRef.current && iframeRef.current.contentWindow) {
        // Correctly stringify commands for postMessage to ensure reliability
        iframeRef.current.contentWindow.postMessage(JSON.stringify({ event: 'command', func: 'seekTo', args: [0, true] }), '*');
        iframeRef.current.contentWindow.postMessage(JSON.stringify({ event: 'command', func: 'playVideo', args: [] }), '*');
    }

    // Play Dubbed Audio
    if (audioBuffer && audioContextRef.current) {
      if (sourceNodeRef.current) {
        sourceNodeRef.current.stop();
      }
      const source = audioContextRef.current.createBufferSource();
      source.buffer = audioBuffer;

      // Connect to gain node if available, otherwise destination
      if (gainNodeRef.current) {
        source.connect(gainNodeRef.current);
      } else {
        source.connect(audioContextRef.current.destination);
      }

      source.start();
      sourceNodeRef.current = source;
    }
  };

  const handleReset = () => {
    if (state.audioUrl) {
      URL.revokeObjectURL(state.audioUrl);
    }
    setState({
      step: AppStep.UPLOAD,
      inputMode: InputMode.FILE,
      isMockMode: true,
      videoFile: null,
      youtubeUrl: '',
      youtubeId: null,
      videoUrl: null,
      transcript: '',
      translatedText: '',
      audioUrl: null,
      isProcessing: false,
      progress: 0,
      logs: [],
      statusMessage: "Ready"
    });
    setAudioBuffer(null);
    setVolume(1.0);
    if (gainNodeRef.current) {
      gainNodeRef.current.gain.value = 1.0;
    }
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-50 flex flex-col items-center">
      {/* Header */}
      <header className="w-full bg-slate-800 border-b border-slate-700 p-4 shadow-lg sticky top-0 z-50">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-gradient-to-tr from-blue-500 to-purple-600 p-2 rounded-lg">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
              </svg>
            </div>
            <div>
              <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-purple-400">
                VaniBridge AI
              </h1>
              <p className="text-xs text-slate-400">Bridging Language Barriers in Education</p>
            </div>
          </div>
          <div className="text-xs text-slate-500 border border-slate-700 rounded px-2 py-1">
            GSA Tech Summit 2026
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="w-full max-w-4xl p-6 flex-grow flex flex-col gap-8">

        {/* Step Indicator */}
        <div className="flex justify-between items-center px-8 relative">
          <div className="absolute top-1/2 left-0 w-full h-1 bg-slate-800 -z-10"></div>
          {[AppStep.UPLOAD, AppStep.PROCESSING, AppStep.RESULT].map((s, idx) => (
            <div key={s} className={`flex flex-col items-center bg-slate-900 px-2`}>
