      progress: 0,
      logs: [],
      statusMessage: "Ready"
    });
    setAudioBuffer(null);
    setVolume(1.0);
    if (gainNodeRef.current) {
      gainNodeRef.current.gain.value = 1.0;
    }
  };

  return (
