    const demoBtn = document.getElementById('demoBtn');
    const languageSelect = document.getElementById('languageSelect');
    const voiceSelect = document.getElementById('voiceSelect');
    const accentToggle = document.getElementById('accentToggle');
    const progressBar = document.getElementById('progressBar');
    const currentStep = document.getElementById('currentStep');
    const originalVideo = document.getElementById('originalVideo');
    const resultVideo = document.getElementById('resultVideo');
    const originalSource = document.getElementById('originalSource');
    const resultSource = document.getElementById('resultSource');
    const origDuration = document.getElementById('origDuration');

    const demoMedia = "https://www.w3schools.com/html/mov_bbb.mp4";
    const demoForOutput = demoMedia; // reuse demo
    const demoCaptions = {
      "English": "Welcome to VaniBridge. This is a sample lecture with labels for demonstration."
    };

    // Initialize
    document.getElementById('year').textContent = new Date().getFullYear();

    // Dropzone interactions
    dropzone.addEventListener('click', () => fileInput.click());
    dropzone.addEventListener('dragover', (e) => {
      e.preventDefault();
      dropzone.classList.add('dragover');
    });
    dropzone.addEventListener('dragleave', () => dropzone.classList.remove('dragover'));
    dropzone.addEventListener('drop', (e) => {
      e.preventDefault();
      dropzone.classList.remove('dragover');
      const file = e.dataTransfer.files[0];
      if (file && file.type.startsWith('video/')) {
        handleFile(file);
      } else {
        alert('Please drop a valid MP4 file.');
      }
    });
    fileInput.addEventListener('change', (e) => {
      const file = e.target.files[0];
      if (file && file.type.startsWith('video/')) {
        handleFile(file);
      } else {
        alert('Please select a valid MP4 file.');
      }
    });

    function handleFile(file) {
      const url = URL.createObjectURL(file);
      setOriginalSource(url);
      currentStep.textContent = 'File uploaded. Ready to generate.';
      resetProgress(0);
    }

    function setOriginalSource(url) {
      originalSource.src = url;
      originalVideo.load();
      originalVideo.addEventListener('loadedmetadata', () => {
        origDuration.textContent = formatTime(originalVideo.duration);
      }, { once: true });
    }

    function formatTime(sec) {
      sec = Math.floor(sec || 0);
      const m = Math.floor(sec / 60);
      const s = (sec % 60).toString().padStart(2, '0');
      return `${m.toString().padStart(2,'0')}:${s}`;
    }

    // Accent toggle
    accentToggle.addEventListener('click', () => {
      accentToggle.classList.toggle('active');
    });

    // Demo button
    demoBtn.addEventListener('click', async () => {
      setOriginalSource(demoMedia);
      originalVideo.load();
      currentStep.textContent = 'Demo video loaded. Ready to generate.';
      resetProgress(0);
      // Auto start preview animations
      originalVideo.play().catch(()=>{});
      resultVideo.play().catch(()=>{});
    });

    // Generate button behavior
    generateBtn.addEventListener('click', async () => {
      const lang = languageSelect.value;
      const style = voiceSelect.value;
      const accentOn = accentToggle.classList.contains('active');

      if (!originalSource.hasSrc) {
        currentStep.textContent = 'Please upload or select a demo video first.';
        return;
      }

      currentStep.textContent = 'Analyzing audio and lip-sync frames...';
      resetProgress(10);
      await simulateStep(1500, 30);

      currentStep.textContent = `Translating and adapting script for ${lang}...`;
      resetProgress(30);
      await simulateStep(1500, 50);

      currentStep.textContent = accentOn ? 'Normalizing accent and rhythm...' : 'Direct translation...';
      resetProgress(50);
      await simulateStep(1200, 70);

      currentStep.textContent = 'Synthesizing voice clip with ' + style + ' style...';
      resetProgress(70);
      await simulateStep(1500, 85);

      currentStep.textContent = 'Reconstructing lip-sync remapped output...';
      resetProgress(85);
      await simulateStep(1400, 100);

      // Replace result source with a demo "AI output" (it's the same for demo; in real world, different audio)
      setResultSource(demoForOutput);
      resultVideo.load();
      currentStep.textContent = 'Generation complete. Preview updated.';
      resultVideo.play().catch(()=>{});
    });

    function setResultSource(url) {
      resultSource.src = url;
      // Add a subtle caption overlay visualization by changing badge
      const badge = document.querySelector('.badge.flex.items-center.gap-2');
      if (badge) {
        badge.innerHTML = '<span class="w-2 h-2 rounded-full bg-emerald-400"></span> Ready';
      }
      // Reflect durations
      try {
        resultVideo.duration = originalVideo.duration || 0;
        resultVideo.addEventListener('loadedmetadata', () => {
          const d = resultVideo.duration;
          origDuration.textContent = formatTime(d);
        }, { once: true });
      } catch(e){}
    }

    function resetProgress(pct) {
      progressBar.style.width = pct + '%';
    }

    async function simulateStep(duration = 1000, targetPct = 50) {
      return new Promise(res => {
        const start = performance.now();
        function tick(now) {
          const t = Math.min(1, (now - start) / duration);
          const current = 10 + t * (targetPct - 10);
          progressBar.style.width = current + '%';
          if (t < 1) requestAnimationFrame(tick); else res();
        }
        requestAnimationFrame(tick);
      });
    }

    // Keyboard accessibility
    dropzone.addEventListener('keydown', (e) => {
      if (e.code === 'Space' || e.code === 'Enter') {
        e.preventDefault();
        fileInput.click();
      }
    });

    // Simulated "realtime" processing hint on hover
    dropzone.addEventListener('mousemove', (e) => {
      if (dropzone.classList.contains('dragover')) return;
      dropzone.style.transform = 'translateY(-2px)';
    });
    dropzone.addEventListener('mouseleave', () => {
      dropzone.style.transform = 'translateY(0)';
    });

    // Utility: update progress on interval while waiting
    setInterval(() => {
      const val = parseFloat(progressBar.style.width) || 0;
      if (val < 20) {
        progressBar.style.width = Math.min(100, val + (Math.random() * 3)) + '%';
      }
    }, 600);
  </script>
</body>
