               )}
            </div>
        )}

        {/* Info Grid */}
        <div className="mt-16 grid md:grid-cols-3 gap-6 opacity-60">
           <div className="p-4 border border-white/5 rounded-xl">
              <h4 className="font-bold text-sm mb-1 text-slate-300">1. Upload & Analyze</h4>
              <p className="text-xs text-slate-500">Video frames and audio are processed to detect context and language.</p>
           </div>
           <div className="p-4 border border-white/5 rounded-xl">
              <h4 className="font-bold text-sm mb-1 text-slate-300">2. Translate & Adapt</h4>
              <p className="text-xs text-slate-500">Educational scripts are translated while preserving technical accuracy.</p>
           </div>
           <div className="p-4 border border-white/5 rounded-xl">
              <h4 className="font-bold text-sm mb-1 text-slate-300">3. Reconstruct</h4>
              <p className="text-xs text-slate-500">AI voice synthesis and lip-sync alignment create a natural regional lesson.</p>
           </div>
        </div>

      </main>

      <footer className="max-w-7xl mx-auto px-6 py-8 border-t border-white/5 mt-8">
         <div className="flex justify-between items-center text-xs text-slate-500">
            <div>© 2026 VaniBridge. Built for GSA India Tech Summit.</div>
            <div className="flex gap-3">
               <span className="badge px-2 py-0.5 rounded">Privacy-First</span>
               <span className="badge px-2 py-0.5 rounded">Gemini Powered</span>
            </div>
         </div>
      </footer>
    </div>
  );
};

