export enum AppStep {
  UPLOAD = 'UPLOAD',
  PROCESSING = 'PROCESSING',
  RESULT = 'RESULT'
}

export enum TargetLanguage {
  HINDI = 'Hindi',
  MARATHI = 'Marathi',
  TAMIL = 'Tamil',
  TELUGU = 'Telugu'
}

export enum InputMode {
  FILE = 'FILE',
  YOUTUBE = 'YOUTUBE'
}

export interface ProcessingState {
  step: AppStep;
  inputMode: InputMode;
  isMockMode: boolean;
  videoFile: File | null;
  youtubeUrl: string;
  youtubeId: string | null;
  videoUrl: string | null;
  detectedLanguage: string | null;
  transcript: string;
  translatedText: string;
  audioUrl: string | null;
  veoPrompt: string | null;
  isProcessing: boolean;
  progress: number; // 0 to 100
  logs: string[];
  statusMessage: string;
}

export interface GeminiError {
  message: string;
}

import { GoogleGenAI, Modality } from "@google/genai";

// Use a function to ensure we always get the latest API key (e.g., after user selection)
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Helper to convert File to Base64
 */
export const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve({
        inlineData: {
          data: base64String,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Step 1: Detect Language & Transcribe Video Audio
 */
export const detectAndTranscribe = async (file: File): Promise<{ language: string; transcript: string }> => {
  const ai = getAI();
  const videoPart = await fileToGenerativePart(file);

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        videoPart,
        { text: "Listen to the audio in this video carefully. 1. Detect the dominant spoken language. 2. Transcribe the **entire** speech in that language accurately, word-for-word. Do not summarize. Return a JSON object with keys 'language' and 'transcript'. Do not add Markdown code blocks." }
      ]
    },
    config: {
      responseMimeType: "application/json"
    }
  });

  const text = response.text || "{}";
  try {
    const json = JSON.parse(text);
    return {
      language: json.language || "Unknown",
      transcript: json.transcript || ""
    };
  } catch (e) {
    console.warn("Failed to parse JSON from Gemini, returning raw text as transcript", text);
    return { language: "Unknown", transcript: text };
  }
};

/**
 * Step 1b: Analyze YouTube URL (Fallback when download fails)
 */
export const analyzeYouTubeUrl = async (url: string): Promise<{ language: string; transcript: string }> => {
  const ai = getAI();
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { text: `I have a YouTube video URL: ${url}. 
            Task:
            1. Use Google Search to find detailed information about this video (full transcript, captions, comprehensive summary, or blog posts describing it).
            2. Detect the likely language of the video.
            3. Generate a Transcript:
               - TARGET: A full, comprehensive transcript of the video's content.
               - If the exact transcript is found, use it.
               - If not, generate a **comprehensive educational script** that covers the *entire* subject matter explained in the video. 
               - **DO NOT** provide a short summary. The output must be detailed and cover the full duration's topic (e.g., multiple paragraphs).
               - **CRITICAL:** Do NOT return error messages like "transcript not found". Always return valid, translatable text relevant to the video's topic.

            Return a JSON object with keys 'language' and 'transcript'. Do not add Markdown code blocks.` }
        ]
      },
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json"
      }
    });

    const text = response.text || "{}";
    let json;
    try {
        json = JSON.parse(text);
    } catch (e) {
        // If parsing fails, use fallback
        return generateGenericTranscript();
    }

    if (!json.transcript || json.transcript.includes("Could not retrieve")) {
        return generateGenericTranscript();
    }

    return {
       language: json.language || "English",
       transcript: json.transcript
    };
  } catch (error) {
    // Check for critical auth errors and rethrow them so the UI can prompt for a new key
    const errMsg = (error as Error).message.toLowerCase();
    if (errMsg.includes("permission denied") || errMsg.includes("403") || errMsg.includes("not found")) {
        throw error;
    }
    console.error("YouTube Analysis Error (using fallback):", error);
    return generateGenericTranscript();
  }
};

/**
 * Generate Visual Prompt for Veo
 */
export const generateVideoPrompt = async (transcript: string): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { text: `Act as an award-winning cinematic director. Based on the educational transcript below, write a highly descriptive visual prompt for a video generation model (Veo).

        Requirements:
        - The video should be a beautiful, motion-rich background that metaphorically or literally represents the core topic.
        - Style: Cinematic, Photorealistic, High Resolution (4K), Slow Motion, Elegant.
        - Content: No text overlays, no people talking, no complex human interactions. Focus on nature, science, technology, or abstract concepts depending on the topic.
        - Length: Keep the prompt under 50 words.

        Transcript Excerpt: "${transcript.substring(0, 500)}..."` }
      ]
    }
  });
  return response.text || "A calm educational classroom background with abstract science symbols, cinematic lighting, 4k resolution";
};

/**
 * Generate Related Video using Veo
 */
export const generateRelatedVideo = async (prompt: string): Promise<Blob> => {
  const ai = getAI();
  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    config: {
      numberOfVideos: 1,
      resolution: '1080p',
      aspectRatio: '16:9'
    }
  });

  // Poll for completion
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!videoUri) throw new Error("Video generation returned no URI");

  // Fetch the actual video bytes
  // IMPORTANT: process.env.API_KEY is dynamic in this environment
  const res = await fetch(`${videoUri}&key=${process.env.API_KEY}`);
  if (!res.ok) throw new Error("Failed to download generated video");

  return await res.blob();
};

/**
 * Step 1c: Generate Generic Transcript (Mock/Simulated)
 */
export const generateGenericTranscript = async (): Promise<{ language: string; transcript: string }> => {
  const ai = getAI();
  const topics = ["The Water Cycle", "Photosynthesis", "Gravity", "The Solar System", "Volcanoes", "Ocean Currents", "Atoms"];
  const randomTopic = topics[Math.floor(Math.random() * topics.length)];

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { text: `Write a **detailed and comprehensive** educational transcript explaining ${randomTopic} to a student. It should be substantial (at least 200 words). Return a JSON object with keys 'language' (value: 'English') and 'transcript' (the text).` }
      ]
    },
    config: {
      responseMimeType: "application/json"
    }
  });

  const text = response.text || "{}";
  try {
     return JSON.parse(text);
  } catch(e) {
     return { 
       language: "English", 
       transcript: "Science helps us understand the world around us. From the smallest atoms to the largest galaxies, everything is connected." 
     };
  }
};

/**
 * Step 2: Translate Text
 */
export const translateText = async (text: string, targetLang: string, sourceLang: string): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { text: `Translate the following ${sourceLang} text to ${targetLang}. Ensure the tone is educational and suitable for rural audiences. Return ONLY the translated text. Do not summarize; translate the full text.\n\nText: "${text}"` }
      ]
    }
  });

  return response.text || "";
};

/**
 * Step 3: Generate Speech (TTS)
 */
export const generateSpeechData = async (text: string): Promise<ArrayBuffer> => {
   const ai = getAI();
   const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: text }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Puck' },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio data returned");

  const binaryString = atob(base64Audio);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes.buffer;
}

/**
 * Helper to generate SRT format from raw text
 */
export const generateSRT = (text: string): string => {
  const sentences = text.match(/[^.!?\n]+[.!?\n]+|[^.!?\n]+$/g);
  if (!sentences) return "";

  let srtContent = "";
  let startTime = 0;

  sentences.forEach((sentence, index) => {
    const trimmed = sentence.trim();
    if (!trimmed) return;

    const wordCount = trimmed.split(/\s+/).length;
    const duration = Math.max(1.5, wordCount * 0.4); 
    const endTime = startTime + duration;

    const formatTime = (seconds: number) => {
       const date = new Date(0);
       date.setMilliseconds(seconds * 1000);
       return date.toISOString().slice(11, 23).replace('.', ',');
    };

    srtContent += `${index + 1}\n`;
    srtContent += `${formatTime(startTime)} --> ${formatTime(endTime)}\n`;
    srtContent += `${trimmed}\n\n`;

    startTime = endTime;
  });

  return srtContent;
};

import React, { useState, useRef, useEffect } from 'react';
import { TargetLanguage, ProcessingState, AppStep, InputMode } from './types';
import { detectAndTranscribe, translateText, generateSpeechData, generateGenericTranscript, analyzeYouTubeUrl, generateSRT, generateVideoPrompt, generateRelatedVideo } from './services/geminiService';
import { UploadIcon, PlayIcon, PauseIcon, LoadingSpinner, YouTubeIcon, LinkIcon, VolumeIcon, DownloadIcon, SkipBackIcon, SkipForwardIcon, SubtitleIcon } from './components/Icon';
import { ProcessingLog } from './components/ProcessingLog';

const MAX_FILE_SIZE = 2000 * 1024 * 1024; 

// Design-specific Volume Control
const VolumeControl: React.FC<{ volume: number; onChange: (val: number) => void }> = ({ volume, onChange }) => (
  <div className="flex items-center gap-2 group">
     <button 
       onClick={() => onChange(volume === 0 ? 1 : 0)}
       className="text-slate-400 hover:text-cyan-300 transition-colors focus:outline-none"
     >
       <VolumeIcon />
     </button>
     <div className="w-20 h-1 bg-slate-700 rounded-full relative overflow-hidden group hover:bg-slate-600 transition-colors">
        <div 
          className="absolute top-0 left-0 h-full bg-cyan-400 rounded-full" 
          style={{ width: `${volume * 100}%` }}
        ></div>
        <input 
          type="range" 
          min="0" 
          max="1" 
          step="0.01" 
          value={volume} 
          onChange={(e) => onChange(parseFloat(e.target.value))}
          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
        />
     </div>
  </div>
);

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.HINDI);
  const [isPlaying, setIsPlaying] = useState<boolean>(false);
  const [previewMode, setPreviewMode] = useState<'dubbed' | 'original'>('dubbed');
  const [state, setState] = useState<ProcessingState>({
    step: AppStep.UPLOAD,
    inputMode: InputMode.FILE,
    isMockMode: true,
    videoFile: null,
    youtubeUrl: '',
    youtubeId: null,
    videoUrl: null,
    detectedLanguage: null,
    transcript: '',
    translatedText: '',
    audioUrl: null,
    veoPrompt: null,
    isProcessing: false,
    progress: 0,
    logs: [],
    statusMessage: "Ready"
  });

  const [audioBuffer, setAudioBuffer] = useState<AudioBuffer | null>(null);
  const [volume, setVolume] = useState<number>(1.0);
  const [currentPlaybackTime, setCurrentPlaybackTime] = useState<number>(0);
  const [duration, setDuration] = useState<number>(0);

  const audioContextRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const iframeRef = useRef<HTMLIFrameElement>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const currentTimeRef = useRef<number>(0);
  const isSeekingRef = useRef<boolean>(false);

  // Initialize AudioContext
  useEffect(() => {
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    const gainNode = ctx.createGain();
    gainNode.gain.value = 1.0; 
    gainNode.connect(ctx.destination);
    audioContextRef.current = ctx;
    gainNodeRef.current = gainNode;
    return () => { audioContextRef.current?.close(); };
  }, []);

  // Audio Mixing Logic
  useEffect(() => {
    // Only apply complex mixing if we have a result
    if (state.step !== AppStep.RESULT) {
       // Allow original audio pass-through if just previewing upload
       if (videoRef.current) {
          videoRef.current.muted = false;
          videoRef.current.volume = volume;
       }
       return;
    }

    const isDubbedMode = previewMode === 'dubbed';

    // 1. Gain Node (TTS Audio)
    if (gainNodeRef.current && audioContextRef.current) {
        const targetGain = isDubbedMode ? volume : 0;
        gainNodeRef.current.gain.setTargetAtTime(targetGain, audioContextRef.current.currentTime, 0.1);
    }
    // 2. Video Element
    if (videoRef.current) {
        videoRef.current.muted = isDubbedMode; 
        videoRef.current.volume = volume;
    }
    // 3. YouTube
    if (state.youtubeId && iframeRef.current?.contentWindow) {
        const muteCommand = isDubbedMode ? 'mute' : 'unMute';
        iframeRef.current.contentWindow.postMessage(JSON.stringify({ event: 'command', func: muteCommand, args: [] }), '*');
        iframeRef.current.contentWindow.postMessage(JSON.stringify({ event: 'command', func: 'setVolume', args: [volume * 100] }), '*');
    }
  }, [previewMode, volume, state.youtubeId, state.step]);

  const handlePause = React.useCallback(async () => {
    await audioContextRef.current?.suspend();
    videoRef.current?.pause();
    iframeRef.current?.contentWindow?.postMessage(JSON.stringify({ event: 'command', func: 'pauseVideo' }), '*');
    setIsPlaying(false);
  }, []);

  // Playback Loop
  useEffect(() => {
    let interval: ReturnType<typeof setInterval>;
    if (isPlaying) {
      interval = setInterval(() => {
        if (videoRef.current && !videoRef.current.paused) {
          currentTimeRef.current = videoRef.current.currentTime;
          if (videoRef.current.duration) setDuration(videoRef.current.duration);
        } else {
          // Dead reckoning for YouTube/Mock
          currentTimeRef.current = (currentTimeRef.current || 0) + 0.1;
          // Approximate duration check if we have audio buffer
          if (audioBuffer && currentTimeRef.current >= audioBuffer.duration) {
             handlePause();
             currentTimeRef.current = 0;
          }
        }
        setCurrentPlaybackTime(currentTimeRef.current);
      }, 100);
    }
    return () => clearInterval(interval);
  }, [isPlaying, audioBuffer, handlePause]);

  // Helpers
  const addLog = (message: string) => {
    setState(prev => ({ ...prev, logs: [...prev.logs, message] }));
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > MAX_FILE_SIZE) {
        alert("File size exceeds 2GB.");
        return;
      }
      const url = URL.createObjectURL(file);
      setState(prev => ({
        ...prev,
        videoFile: file,
        videoUrl: url,
        youtubeId: null,
        logs: [`Loaded: ${file.name}`]
      }));
    }
  };

  // ... (Existing audio helper functions: createWavUrl, decodeAudio)
  const createWavUrl = (pcmData: ArrayBuffer): string => {
    const sampleRate = 24000;
    const numChannels = 1;
    const bitsPerSample = 16;
    const header = new ArrayBuffer(44);
    const view = new DataView(header);
    const writeString = (offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) {
        view.setUint8(offset + i, string.charCodeAt(i));
      }
    };
    writeString(0, 'RIFF');
    view.setUint32(4, 36 + pcmData.byteLength, true); 
    writeString(8, 'WAVE');
    writeString(12, 'fmt ');
    view.setUint32(16, 16, true); 
    view.setUint16(20, 1, true); 
    view.setUint16(22, numChannels, true); 
    view.setUint32(24, sampleRate, true); 
    view.setUint32(28, sampleRate * numChannels * (bitsPerSample / 8), true); 
    view.setUint16(32, numChannels * (bitsPerSample / 8), true); 
    view.setUint16(34, bitsPerSample, true); 
    writeString(36, 'data');
    view.setUint32(40, pcmData.byteLength, true);
    const blob = new Blob([header, pcmData], { type: 'audio/wav' });
    return URL.createObjectURL(blob);
  };

  const decodeAudio = async (arrayBuffer: ArrayBuffer) => {
    if (!audioContextRef.current) return;
    try {
      const pcmData = new Int16Array(arrayBuffer);
      const buffer = audioContextRef.current.createBuffer(1, pcmData.length, 24000);
      const channelData = buffer.getChannelData(0);
      for (let i = 0; i < pcmData.length; i++) {
        channelData[i] = pcmData[i] / 32768.0;
      }
      setAudioBuffer(buffer);
      setDuration(buffer.duration);
    } catch (e) {
      console.error(e);
      addLog("Error decoding audio.");
    }
  };

  const getYouTubeId = (url: string) => {
    // Robust regex for various YouTube URL formats
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=|shorts\/)([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? match[2] : null;
  };

  // Video Fetcher
  const fetchVideoFromUrl = async (url: string, onProgress: (p: number) => void): Promise<File> => {
    const response = await fetch(url);
    if (!response.ok) throw new Error(`Network error: ${response.status}`);
    const reader = response.body?.getReader();
    const total = parseInt(response.headers.get('content-length') || '0', 10);
    let loaded = 0;
    const chunks = [];
    if (!reader) {
       const blob = await response.blob();
       return new File([blob], "video.mp4", { type: blob.type });
    }
    while(true) {
        const {done, value} = await reader.read();
        if (done) break;
        if (value) {
            chunks.push(value);
            loaded += value.length;
            if (total) onProgress((loaded/total)*100);
        }
    }
    onProgress(100);
    const blob = new Blob(chunks, { type: 'video/mp4' });
    return new File([blob], "downloaded.mp4", { type: 'video/mp4' });
  };

  const startProcessing = async () => {
    setState(prev => ({ ...prev, step: AppStep.PROCESSING, isProcessing: true, progress: 0, statusMessage: "Initializing...", veoPrompt: null }));
    setIsPlaying(false);
    currentTimeRef.current = 0;
    setCurrentPlaybackTime(0);
    setPreviewMode('dubbed');

    try {
        let processingFile = state.videoFile;

        if (state.inputMode === InputMode.YOUTUBE) {
            // 1. Check for Paid API Key (Required for Veo)
            if ((window as any).aistudio && !(await (window as any).aistudio.hasSelectedApiKey())) {
               setState(p => ({...p, statusMessage: "Waiting for API Key..."}));
               await (window as any).aistudio.openSelectKey();
               // Key propagation is assumed to be handled by the environment/SDK
            }

            const url = state.youtubeUrl.trim();
            if (!url) throw new Error("Invalid URL");
            const ytid = getYouTubeId(url);

            // Set ID initially to show thumbnail, but we will replace this with Veo result later
            setState(p => ({...p, youtubeId: ytid}));

            // 2. Analyze & Generate
            setState(p => ({...p, progress: 10, statusMessage: "Analyzing YouTube content..."}));
            const { transcript, language } = await analyzeYouTubeUrl(url);

            // 3. Generate Visuals (Veo)
            setState(p => ({...p, transcript, detectedLanguage: language, progress: 30, statusMessage: "Generating cinematic background (Veo)..."}));
            const videoPrompt = await generateVideoPrompt(transcript);
            setState(p => ({...p, veoPrompt: videoPrompt}));
            addLog(`Veo Prompt: ${videoPrompt}`);

            const videoBlob = await generateRelatedVideo(videoPrompt);
            const generatedVideoUrl = URL.createObjectURL(videoBlob);
            processingFile = new File([videoBlob], "veo_generated.mp4", { type: "video/mp4" });

            // Re-assign to use generated video instead of YouTube iframe
            setState(p => ({
               ...p, 
               videoUrl: generatedVideoUrl, 
               youtubeId: null, // CLEAR ID to remove iframe and avoid error 153
               videoFile: processingFile,
               progress: 60,
               statusMessage: `Translating from ${language}...`
            }));
        }

        if (!processingFile) throw new Error("No file.");

        // 4. Translate & TTS (Standard Flow)
        // If we came from YouTube, we already have the transcript/language
        let transcript = state.transcript;
        let detectedLanguage = state.detectedLanguage || "Unknown";

        if (state.inputMode === InputMode.FILE) {
             const res = await detectAndTranscribe(processingFile);
             transcript = res.transcript;
             detectedLanguage = res.language;
             setState(p => ({...p, transcript, detectedLanguage, progress: 60, statusMessage: `Translating from ${detectedLanguage}...`}));
        }

        const translated = await translateText(transcript, targetLang, detectedLanguage);
        setState(p => ({...p, translatedText: translated, progress: 80, statusMessage: "Synthesizing voice..."}));

        const audioData = await generateSpeechData(translated);
        const wavUrl = createWavUrl(audioData);
        await decodeAudio(audioData);

        // 5. Finalize
        setState(p => ({...p, progress: 100, statusMessage: "Lip-syncing...", audioUrl: wavUrl}));
        await new Promise(r => setTimeout(r, 1000));

        setState(p => ({...p, step: AppStep.RESULT, isProcessing: false, statusMessage: "Ready"}));

    } catch (e) {
        const err = e as Error;
        console.error(err);

        // Handle API Key/Permission errors specifically
        if (err.message.toLowerCase().includes("permission denied") || 
            err.message.includes("403") || 
            err.message.includes("not found")) {

             if ((window as any).aistudio) {
                 addLog("Authentication failed. Requesting new key...");
                 // Force the key selection dialog to open again
                 await (window as any).aistudio.openSelectKey();

                 setState(p => ({...p, isProcessing: false, statusMessage: "Auth Error", logs: [...p.logs, "Permission denied. Please select a valid paid API key and try again."] }));
             } else {
                 setState(p => ({...p, isProcessing: false, statusMessage: "Auth Error", logs: [...p.logs, `Permission Denied: ${err.message}`] }));
             }
        } else {
             setState(p => ({...p, isProcessing: false, statusMessage: "Failed", logs: [...p.logs, `Error: ${err.message}`] }));
        }
    }
  };

  // Playback Controls
  const handlePlayPause = async () => {
     if (isPlaying) {
         await handlePause();
     } else {
         if (audioContextRef.current?.state === 'suspended') await audioContextRef.current.resume();

         // Start Audio
         if (audioBuffer && !sourceNodeRef.current && state.step === AppStep.RESULT) {
             const src = audioContextRef.current!.createBufferSource();
             src.buffer = audioBuffer;
             src.connect(gainNodeRef.current || audioContextRef.current!.destination);
             src.start(0, currentTimeRef.current);
             src.onended = () => { if(!isSeekingRef.current) setIsPlaying(false); };
             sourceNodeRef.current = src;
         }

         videoRef.current?.play();
         if (state.youtubeId) {
             iframeRef.current?.contentWindow?.postMessage(JSON.stringify({ event: 'command', func: 'seekTo', args: [currentTimeRef.current, true] }), '*');
             iframeRef.current?.contentWindow?.postMessage(JSON.stringify({ event: 'command', func: 'playVideo' }), '*');
         }
         setIsPlaying(true);
     }
  };

  const handleSeek = (time: number) => {
      isSeekingRef.current = true;
      const t = Math.max(0, Math.min(time, duration || 100));
      currentTimeRef.current = t;
      setCurrentPlaybackTime(t);

      if (videoRef.current) videoRef.current.currentTime = t;
      if (state.youtubeId) iframeRef.current?.contentWindow?.postMessage(JSON.stringify({ event: 'command', func: 'seekTo', args: [t, true] }), '*');

      // Audio Seek
      if (sourceNodeRef.current) {
          try { sourceNodeRef.current.stop(); } catch(e){}
          sourceNodeRef.current = null;
      }
      if (isPlaying && audioBuffer && state.step === AppStep.RESULT) {
          const src = audioContextRef.current!.createBufferSource();
          src.buffer = audioBuffer;
          src.connect(gainNodeRef.current || audioContextRef.current!.destination);
          src.start(0, t);
          sourceNodeRef.current = src;
      }
      setTimeout(() => isSeekingRef.current = false, 50);
  };

  const formatTime = (s: number) => {
      const m = Math.floor(s / 60);
      const sec = Math.floor(s % 60);
      return `${m}:${sec.toString().padStart(2, '0')}`;
  };

  const handleReset = () => {
      setState(p => ({...p, step: AppStep.UPLOAD, transcript: '', translatedText: '', audioUrl: null, logs: [], progress: 0, statusMessage: "Ready", veoPrompt: null }));
      setAudioBuffer(null);
      setCurrentPlaybackTime(0);
      setIsPlaying(false);
  };

  const handleDownloadSRT = (text: string, filename: string) => {
    const srtContent = generateSRT(text);
    const blob = new Blob([srtContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="min-h-screen text-slate-100 overflow-x-hidden selection:bg-cyan-500/30">

      {/* Dynamic Background Elements */}
      <div className="fixed inset-0 pointer-events-none overflow-hidden">
        <div className="halftone w-[800px] h-[800px] rounded-full opacity-20 blur-3xl -top-40 -left-40 absolute animate-pulse"></div>
        <div className="halftone w-[600px] h-[600px] rounded-full opacity-20 blur-3xl bottom-0 -right-20 absolute"></div>
      </div>

      <header className="relative z-10 border-b border-white/5 bg-[#0b1020]/80 backdrop-blur-md sticky top-0">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-4">
             <div className="w-10 h-10 rounded-xl glass flex items-center justify-center text-cyan-300 shadow-[0_0_15px_rgba(110,231,240,0.3)]">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="currentColor"><path d="M12 3a9 9 0 1 0 9 9h-2a7 7 0 1 1-7-7V3z"/><path d="M12 7l4 4H8l4-4zm0 8v4m-4-4h8"/></svg>
             </div>
             <div>
                <h1 className="text-2xl font-bold tracking-tight bg-gradient-to-r from-cyan-200 to-violet-300 bg-clip-text text-transparent">VaniBridge</h1>
                <p className="text-xs text-slate-400 font-medium tracking-wide">AI VIDEO LOCALIZATION</p>
             </div>
          </div>
          <div className="flex items-center gap-2 px-3 py-1.5 rounded-full border border-white/10 bg-white/5 backdrop-blur-sm">
             <span className={`status-dot ${state.isProcessing ? 'processing animate-pulse' : 'live'}`}></span>
             <span className="text-xs font-medium text-slate-300">{state.isProcessing ? 'Processing' : 'Live Inference'}</span>
          </div>
        </div>
      </header>

      <main className="relative z-10 max-w-7xl mx-auto px-6 py-8">
        <div className="grid lg:grid-cols-2 gap-8 items-start">

          {/* LEFT COLUMN: Controls & Input */}
          <section className="glass rounded-2xl p-1 flex flex-col gap-6 animate-fadeIn">
            <div className="p-6 pb-0">
                <div className="flex items-center justify-between mb-4">
                   <h2 className="text-lg font-bold text-slate-100">Configuration</h2>
                   <div className="flex bg-slate-800/50 rounded-lg p-1 border border-white/5">
                      <button 
                        onClick={() => setState(p => ({...p, inputMode: InputMode.FILE}))}
                        className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${state.inputMode === InputMode.FILE ? 'bg-slate-700 text-cyan-300 shadow-sm' : 'text-slate-400 hover:text-white'}`}
                      >File</button>
                      <button 
                        onClick={() => setState(p => ({...p, inputMode: InputMode.YOUTUBE}))}
                        className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${state.inputMode === InputMode.YOUTUBE ? 'bg-slate-700 text-red-400 shadow-sm' : 'text-slate-400 hover:text-white'}`}
                      >YouTube</button>
                   </div>
                </div>

                {state.inputMode === InputMode.FILE ? (
                   <div className="dropzone rounded-xl p-8 text-center cursor-pointer relative group" onClick={() => document.getElementById('fileUpload')?.click()}>
                      <input id="fileUpload" type="file" accept="video/mp4" className="hidden" onChange={handleFileUpload} />
                      <div className="w-14 h-14 mx-auto rounded-2xl bg-white/5 flex items-center justify-center mb-3 group-hover:scale-110 transition-transform">
                         <UploadIcon />
                      </div>
                      <p className="text-sm font-medium text-slate-200">{state.videoFile ? state.videoFile.name : "Drop English Lecture MP4"}</p>
                      <p className="text-xs text-slate-500 mt-1">Max 2GB • MP4 Format</p>
                   </div>
                ) : (
                   <div className="bg-white/5 border border-white/10 rounded-xl p-6 relative">
                      <label className="text-xs font-bold text-slate-400 uppercase mb-2 block">Video URL</label>
                      <div className="relative">
                         <input 
                           type="text" 
                           value={state.youtubeUrl}
                           onChange={(e) => setState(p => ({...p, youtubeUrl: e.target.value}))}
                           className="field w-full rounded-lg py-3 pl-10 pr-4 text-sm focus:bg-slate-900/50"
                           placeholder="https://youtube.com/watch?v=..."
                         />
                         <div className="absolute left-3 top-3 text-slate-500"><LinkIcon /></div>
                      </div>
                   </div>
                )}
            </div>

            <div className="px-6 grid grid-cols-2 gap-4">
                <div>
                   <label className="text-xs text-slate-400 font-medium mb-1.5 block">Learning Language</label>
                   <select 
                     value={targetLang}
                     onChange={(e) => setTargetLang(e.target.value as TargetLanguage)}
                     className="field w-full rounded-lg p-2.5 text-sm bg-slate-900/50 appearance-none cursor-pointer"
                   >
                     {Object.values(TargetLanguage).map(l => <option key={l} value={l}>{l}</option>)}
                   </select>
                </div>
                <div>
                   <label className="text-xs text-slate-400 font-medium mb-1.5 block">Processing Mode</label>
                   <div className="flex items-center justify-between field rounded-lg p-2 bg-slate-900/50">
                      <span className="text-xs text-slate-300 ml-1">Mock Lip-Sync</span>
                      <div 
                        className={`toggle ${state.isMockMode ? 'active' : ''}`}
                        onClick={() => setState(p => ({...p, isMockMode: !p.isMockMode}))}
                      ></div>
                   </div>
                </div>
            </div>

            <div className="p-6 pt-2">
                <button 
                  onClick={startProcessing}
                  disabled={state.step !== AppStep.UPLOAD || (!state.videoFile && !state.youtubeUrl)}
                  className="btn-primary w-full py-3.5 rounded-xl text-sm font-bold tracking-wide uppercase shadow-lg disabled:opacity-50 disabled:shadow-none"
                >
                  {state.isProcessing ? 'Generating...' : 'Generate Regional Lesson'}
                </button>
            </div>

            {/* AI Director Insight Panel - Shows the "Script to Video" logic */}
            {state.veoPrompt && (
              <div className="mx-6 mb-6 p-4 rounded-xl border border-white/10 bg-indigo-900/20 animate-fadeIn">
                 <div className="flex items-center justify-between mb-2">
                    <h3 className="text-xs font-bold text-indigo-300 uppercase tracking-wider flex items-center gap-2">
                       <span className="w-2 h-2 rounded-full bg-indigo-400 animate-pulse"></span>
                       AI Creative Director
                    </h3>
                    <span className="text-[10px] text-indigo-400/60 bg-indigo-900/40 px-2 py-0.5 rounded">Veo-3.1</span>
                 </div>
                 <div className="text-xs text-indigo-200/80 italic border-l-2 border-indigo-500/30 pl-3 py-1">
                    "{state.veoPrompt}"
                 </div>
              </div>
            )}
          </section>

          {/* RIGHT COLUMN: Output Preview */}
          <section className="glass rounded-2xl overflow-hidden flex flex-col h-full min-h-[400px]">
             <div className="p-4 border-b border-white/5 flex justify-between items-center bg-white/[0.02]">
                <h2 className="text-sm font-bold flex items-center gap-2">
                   Output Preview
                   {state.step === AppStep.RESULT && <span className="badge text-[10px] px-2 py-0.5 rounded-full">Ready</span>}
                </h2>
                {state.step === AppStep.RESULT && (
                   <div className="flex gap-2">
                      <button onClick={() => setPreviewMode('original')} className={`text-xs px-2 py-1 rounded transition-colors ${previewMode === 'original' ? 'bg-white/10 text-white' : 'text-slate-500 hover:text-slate-300'}`}>Original</button>
                      <button onClick={() => setPreviewMode('dubbed')} className={`text-xs px-2 py-1 rounded transition-colors ${previewMode === 'dubbed' ? 'bg-cyan-500/20 text-cyan-300' : 'text-slate-500 hover:text-slate-300'}`}>AI Dubbed</button>
                   </div>
                )}
             </div>

             <div className="relative flex-grow bg-black flex items-center justify-center group">
                 {state.youtubeId ? (
                    <iframe 
                      ref={iframeRef}
                      className="w-full h-full absolute inset-0 pointer-events-none"
                      src={`https://www.youtube.com/embed/${state.youtubeId}?enablejsapi=1&controls=0&modestbranding=1&rel=0&origin=${window.location.origin}`} 
                    />
                 ) : state.videoUrl ? (
                    <video ref={videoRef} src={state.videoUrl} className="w-full h-full absolute inset-0 object-contain" playsInline muted={false} />
                 ) : (
                    <div className="text-center p-8">
                       <div className="w-16 h-16 mx-auto rounded-full border border-white/10 flex items-center justify-center mb-4 text-slate-600">
                          <PlayIcon />
                       </div>
                       <p className="text-slate-500 text-sm">Preview will appear here</p>
                    </div>
                 )}

                 {/* Overlays */}
                 {state.step === AppStep.PROCESSING && (
                    <div className="absolute inset-0 bg-black/80 backdrop-blur-sm z-20 flex flex-col items-center justify-center p-8">
                       <div className="w-full max-w-xs space-y-4">
                          <div className="flex justify-between text-xs font-mono text-cyan-300">
                             <span>{state.statusMessage}</span>
                             <span>{Math.round(state.progress)}%</span>
                          </div>
                          <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden">
                             <div className="h-full bg-gradient-to-r from-cyan-400 to-violet-500 transition-all duration-300" style={{ width: `${state.progress}%` }}></div>
                          </div>
                          <div className="h-32 overflow-hidden relative">
                             <ProcessingLog logs={state.logs} isProcessing={true} />
                          </div>
                       </div>
                    </div>
                 )}

                 {/* Custom Controls Overlay */}
                 {(state.videoUrl || state.youtubeId) && state.step !== AppStep.PROCESSING && (
                    <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-transparent to-black/20 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex flex-col justify-end p-4 z-10">
                       <div className="flex items-center gap-4 mb-2">
                           <button onClick={handlePlayPause} className="w-10 h-10 flex items-center justify-center rounded-full bg-white text-black hover:scale-105 transition-transform">
                              {isPlaying ? <PauseIcon /> : <PlayIcon />}
                           </button>
                           <div className="flex-grow">
                              <input 
                                type="range" 
                                min="0" 
                                max={duration || 100} 
                                value={currentPlaybackTime} 
                                onChange={(e) => handleSeek(parseFloat(e.target.value))}
                                className="w-full h-1 bg-white/20 rounded-full appearance-none cursor-pointer accent-cyan-400 hover:h-1.5 transition-all"
                              />
                           </div>
                           <div className="text-xs font-mono text-white/80 w-16 text-right">
                              {formatTime(currentPlaybackTime)}
                           </div>
                       </div>
                       <div className="flex justify-between items-center">
                          <div className="flex gap-2">
                             <button onClick={() => handleSeek(currentPlaybackTime - 10)} className="p-1.5 hover:bg-white/10 rounded text-slate-300"><SkipBackIcon /></button>
                             <button onClick={() => handleSeek(currentPlaybackTime + 10)} className="p-1.5 hover:bg-white/10 rounded text-slate-300"><SkipForwardIcon /></button>
                          </div>
                          <VolumeControl volume={volume} onChange={setVolume} />
                       </div>
                    </div>
                 )}
             </div>

             {/* Output Text Tabs */}
             {state.step === AppStep.RESULT && (
                <div className="h-48 border-t border-white/5 bg-slate-900/50 flex">
                   <div className="w-1/2 border-r border-white/5 p-4 overflow-y-auto custom-scrollbar relative group">
                      <div className="flex justify-between items-center mb-2">
                        <h3 className="text-[10px] uppercase font-bold text-slate-500">Transcription ({state.detectedLanguage})</h3>
                        <button onClick={() => handleDownloadSRT(state.transcript, `transcription_${state.detectedLanguage}.srt`)} title="Export SRT" className="text-slate-500 hover:text-white transition-colors"><SubtitleIcon /></button>
                      </div>
                      <p className="text-xs text-slate-300 leading-relaxed font-mono">{state.transcript}</p>
                   </div>
                   <div className="w-1/2 p-4 overflow-y-auto custom-scrollbar bg-cyan-500/[0.02] relative group">
                      <div className="flex justify-between items-center mb-2">
                         <h3 className="text-[10px] uppercase font-bold text-cyan-700/70">Translation ({targetLang})</h3>
                         <button onClick={() => handleDownloadSRT(state.translatedText, `translation_${targetLang}.srt`)} title="Export SRT" className="text-cyan-700/70 hover:text-cyan-300 transition-colors"><SubtitleIcon /></button>
                      </div>
                      <p className="text-xs text-cyan-100/80 leading-relaxed font-mono">{state.translatedText}</p>
                   </div>
                </div>
             )}
          </section>
        </div>

        {/* Reset / Download Actions Footer */}
        {state.step === AppStep.RESULT && (
            <div className="mt-8 flex justify-end gap-4 animate-fadeIn">
               <button onClick={handleReset} className="px-6 py-3 rounded-xl border border-white/10 hover:bg-white/5 text-sm font-medium transition-colors">Process Another</button>

               {/* Video Download Button (Only visible if videoUrl exists and was generated via Veo/inputMode is Youtube) */}
               {state.videoUrl && state.inputMode === InputMode.YOUTUBE && (
                   <a href={state.videoUrl} download="generated_background.mp4" className="btn-primary px-6 py-3 rounded-xl text-sm font-bold flex items-center gap-2 bg-gradient-to-r from-indigo-500 to-purple-600 border-none">
                     <DownloadIcon /> Download Background Video
                  </a>
               )}

               {state.audioUrl && (
                  <a href={state.audioUrl} download={`vanibridge_${targetLang}.wav`} className="btn-primary px-6 py-3 rounded-xl text-sm font-bold flex items-center gap-2">
                     <DownloadIcon /> Download Audio Lesson
                  </a>
               )}
            </div>
        )}

        {/* Info Grid */}
        <div className="mt-16 grid md:grid-cols-3 gap-6 opacity-60">
           <div className="p-4 border border-white/5 rounded-xl">
              <h4 className="font-bold text-sm mb-1 text-slate-300">1. Upload & Analyze</h4>
              <p className="text-xs text-slate-500">Video frames and audio are processed to detect context and language.</p>
           </div>
           <div className="p-4 border border-white/5 rounded-xl">
              <h4 className="font-bold text-sm mb-1 text-slate-300">2. Translate & Adapt</h4>
              <p className="text-xs text-slate-500">Educational scripts are translated while preserving technical accuracy.</p>
           </div>
           <div className="p-4 border border-white/5 rounded-xl">
              <h4 className="font-bold text-sm mb-1 text-slate-300">3. Reconstruct</h4>
              <p className="text-xs text-slate-500">AI voice synthesis and lip-sync alignment create a natural regional lesson.</p>
           </div>
        </div>

      </main>

      <footer className="max-w-7xl mx-auto px-6 py-8 border-t border-white/5 mt-8">
         <div className="flex justify-between items-center text-xs text-slate-500">
            <div>© 2026 VaniBridge. Built for GSA India Tech Summit.</div>
            <div className="flex gap-3">
               <span className="badge px-2 py-0.5 rounded">Privacy-First</span>
               <span className="badge px-2 py-0.5 rounded">Gemini Powered</span>
            </div>
         </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { TargetLanguage, ProcessingState, AppStep, InputMode } from './types';
import { detectAndTranscribe, translateText, generateSpeechData, generateGenericTranscript, analyzeYouTubeUrl, generateSRT, generateVideoPrompt, generateRelatedVideo } from './services/geminiService';
import { UploadIcon, PlayIcon, PauseIcon, LoadingSpinner, YouTubeIcon, LinkIcon, VolumeIcon, DownloadIcon, SkipBackIcon, SkipForwardIcon, SubtitleIcon } from './components/Icon';
import { ProcessingLog } from './components/ProcessingLog';

const MAX_FILE_SIZE = 2000 * 1024 * 1024; 

// Design-specific Volume Control
const VolumeControl: React.FC<{ volume: number; onChange: (val: number) => void }> = ({ volume, onChange }) => (
  <div className="flex items-center gap-2 group">
     <button 
       onClick={() => onChange(volume === 0 ? 1 : 0)}
       className="text-slate-400 hover:text-cyan-300 transition-colors focus:outline-none"
     >
       <VolumeIcon />
     </button>
     <div className="w-20 h-1 bg-slate-700 rounded-full relative overflow-hidden group hover:bg-slate-600 transition-colors">
        <div 
          className="absolute top-0 left-0 h-full bg-cyan-400 rounded-full" 
          style={{ width: `${volume * 100}%` }}
        ></div>
        <input 
          type="range" 
          min="0" 
          max="1" 
          step="0.01" 
          value={volume} 
          onChange={(e) => onChange(parseFloat(e.target.value))}
          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
        />
     </div>
  </div>
);

const App: React.FC = () => {
  const [targetLang, setTargetLang] = useState<TargetLanguage>(TargetLanguage.HINDI);
  const [isPlaying, setIsPlaying] = useState<boolean>(false);
  const [previewMode, setPreviewMode] = useState<'dubbed' | 'original'>('dubbed');
  const [state, setState] = useState<ProcessingState>({
    step: AppStep.UPLOAD,
    inputMode: InputMode.FILE,
    isMockMode: true,
    videoFile: null,
    youtubeUrl: '',
    youtubeId: null,
    videoUrl: null,
    detectedLanguage: null,
    transcript: '',
    translatedText: '',
    audioUrl: null,
    veoPrompt: null,
    isProcessing: false,
    progress: 0,
    logs: [],
    statusMessage: "Ready"
  });

  const [audioBuffer, setAudioBuffer] = useState<AudioBuffer | null>(null);
  const [volume, setVolume] = useState<number>(1.0);
  const [currentPlaybackTime, setCurrentPlaybackTime] = useState<number>(0);
  const [duration, setDuration] = useState<number>(0);

  const audioContextRef = useRef<AudioContext | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const iframeRef = useRef<HTMLIFrameElement>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const currentTimeRef = useRef<number>(0);
  const isSeekingRef = useRef<boolean>(false);

  // Initialize AudioContext
  useEffect(() => {
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    const gainNode = ctx.createGain();
    gainNode.gain.value = 1.0; 
    gainNode.connect(ctx.destination);
    audioContextRef.current = ctx;
    gainNodeRef.current = gainNode;
    return () => { audioContextRef.current?.close(); };
  }, []);

  // Audio Mixing Logic
  useEffect(() => {
    // Only apply complex mixing if we have a result
    if (state.step !== AppStep.RESULT) {
       // Allow original audio pass-through if just previewing upload
       if (videoRef.current) {
          videoRef.current.muted = false;
          videoRef.current.volume = volume;
       }
       return;
    }

    const isDubbedMode = previewMode === 'dubbed';

    // 1. Gain Node (TTS Audio)
    if (gainNodeRef.current && audioContextRef.current) {
        const targetGain = isDubbedMode ? volume : 0;
        gainNodeRef.current.gain.setTargetAtTime(targetGain, audioContextRef.current.currentTime, 0.1);
    }
    // 2. Video Element
    if (videoRef.current) {
        videoRef.current.muted = isDubbedMode; 
        videoRef.current.volume = volume;
    }
    // 3. YouTube
    if (state.youtubeId && iframeRef.current?.contentWindow) {
        const muteCommand = isDubbedMode ? 'mute' : 'unMute';
        iframeRef.current.contentWindow.postMessage(JSON.stringify({ event: 'command', func: muteCommand, args: [] }), '*');
        iframeRef.current.contentWindow.postMessage(JSON.stringify({ event: 'command', func: 'setVolume', args: [volume * 100] }), '*');
    }
  }, [previewMode, volume, state.youtubeId, state.step]);

  const handlePause = React.useCallback(async () => {
    await audioContextRef.current?.suspend();
    videoRef.current?.pause();
    iframeRef.current?.contentWindow?.postMessage(JSON.stringify({ event: 'command', func: 'pauseVideo' }), '*');
    setIsPlaying(false);
  }, []);

  // Playback Loop
  useEffect(() => {
    let interval: ReturnType<typeof setInterval>;
    if (isPlaying) {
      interval = setInterval(() => {
        if (videoRef.current && !videoRef.current.paused) {
          currentTimeRef.current = videoRef.current.currentTime;
          if (videoRef.current.duration) setDuration(videoRef.current.duration);
        } else {
          // Dead reckoning for YouTube/Mock
          currentTimeRef.current = (currentTimeRef.current || 0) + 0.1;
          // Approximate duration check if we have audio buffer
          if (audioBuffer && currentTimeRef.current >= audioBuffer.duration) {
             handlePause();
             currentTimeRef.current = 0;
          }
        }
        setCurrentPlaybackTime(currentTimeRef.current);
      }, 100);
    }
    return () => clearInterval(interval);
  }, [isPlaying, audioBuffer, handlePause]);

  // Helpers
  const addLog = (message: string) => {
    setState(prev => ({ ...prev, logs: [...prev.logs, message] }));
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (file.size > MAX_FILE_SIZE) {
        alert("File size exceeds 2GB.");
        return;
      }
      const url = URL.createObjectURL(file);
      setState(prev => ({
        ...prev,
        videoFile: file,
        videoUrl: url,
        youtubeId: null,
        logs: [`Loaded: ${file.name}`]
      }));
    }
  };

  // ... (Existing audio helper functions: createWavUrl, decodeAudio)
  const createWavUrl = (pcmData: ArrayBuffer): string => {
    const sampleRate = 24000;
    const numChannels = 1;
    const bitsPerSample = 16;
    const header = new ArrayBuffer(44);
    const view = new DataView(header);
    const writeString = (offset: number, string: string) => {
      for (let i = 0; i < string.length; i++) {
        view.setUint8(offset + i, string.charCodeAt(i));
      }
    };
    writeString(0, 'RIFF');
    view.setUint32(4, 36 + pcmData.byteLength, true); 
    writeString(8, 'WAVE');
    writeString(12, 'fmt ');
    view.setUint32(16, 16, true); 
    view.setUint16(20, 1, true); 
    view.setUint16(22, numChannels, true); 
    view.setUint32(24, sampleRate, true); 
    view.setUint32(28, sampleRate * numChannels * (bitsPerSample / 8), true); 
    view.setUint16(32, numChannels * (bitsPerSample / 8), true); 
    view.setUint16(34, bitsPerSample, true); 
    writeString(36, 'data');
    view.setUint32(40, pcmData.byteLength, true);
    const blob = new Blob([header, pcmData], { type: 'audio/wav' });
    return URL.createObjectURL(blob);
  };

  const decodeAudio = async (arrayBuffer: ArrayBuffer) => {
    if (!audioContextRef.current) return;
    try {
      const pcmData = new Int16Array(arrayBuffer);
      const buffer = audioContextRef.current.createBuffer(1, pcmData.length, 24000);
      const channelData = buffer.getChannelData(0);
      for (let i = 0; i < pcmData.length; i++) {
        channelData[i] = pcmData[i] / 32768.0;
      }
      setAudioBuffer(buffer);
      setDuration(buffer.duration);
    } catch (e) {
      console.error(e);
      addLog("Error decoding audio.");
    }
  };

  const getYouTubeId = (url: string) => {
    // Robust regex for various YouTube URL formats
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=|shorts\/)([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? match[2] : null;
  };

  // Video Fetcher
  const fetchVideoFromUrl = async (url: string, onProgress: (p: number) => void): Promise<File> => {
    const response = await fetch(url);
    if (!response.ok) throw new Error(`Network error: ${response.status}`);
    const reader = response.body?.getReader();
    const total = parseInt(response.headers.get('content-length') || '0', 10);
    let loaded = 0;
    const chunks = [];
    if (!reader) {
       const blob = await response.blob();
       return new File([blob], "video.mp4", { type: blob.type });
    }
    while(true) {
        const {done, value} = await reader.read();
        if (done) break;
        if (value) {
            chunks.push(value);
            loaded += value.length;
            if (total) onProgress((loaded/total)*100);
        }
    }
    onProgress(100);
    const blob = new Blob(chunks, { type: 'video/mp4' });
    return new File([blob], "downloaded.mp4", { type: 'video/mp4' });
  };

  const startProcessing = async () => {
    setState(prev => ({ ...prev, step: AppStep.PROCESSING, isProcessing: true, progress: 0, statusMessage: "Initializing...", veoPrompt: null }));
    setIsPlaying(false);
    currentTimeRef.current = 0;
    setCurrentPlaybackTime(0);
    setPreviewMode('dubbed');

    try {
        let processingFile = state.videoFile;

        if (state.inputMode === InputMode.YOUTUBE) {
            // 1. Check for Paid API Key (Required for Veo)
            if ((window as any).aistudio && !(await (window as any).aistudio.hasSelectedApiKey())) {
               setState(p => ({...p, statusMessage: "Waiting for API Key..."}));
               await (window as any).aistudio.openSelectKey();
               // Key propagation is assumed to be handled by the environment/SDK
            }

            const url = state.youtubeUrl.trim();
            if (!url) throw new Error("Invalid URL");
            const ytid = getYouTubeId(url);

            // Set ID initially to show thumbnail, but we will replace this with Veo result later
            setState(p => ({...p, youtubeId: ytid}));

            // 2. Analyze & Generate
            setState(p => ({...p, progress: 10, statusMessage: "Analyzing YouTube content..."}));
            const { transcript, language } = await analyzeYouTubeUrl(url);

            // 3. Generate Visuals (Veo)
            setState(p => ({...p, transcript, detectedLanguage: language, progress: 30, statusMessage: "Generating cinematic background (Veo)..."}));
            const videoPrompt = await generateVideoPrompt(transcript);
            setState(p => ({...p, veoPrompt: videoPrompt}));
            addLog(`Veo Prompt: ${videoPrompt}`);

            const videoBlob = await generateRelatedVideo(videoPrompt);
            const generatedVideoUrl = URL.createObjectURL(videoBlob);
            processingFile = new File([videoBlob], "veo_generated.mp4", { type: "video/mp4" });

            // Re-assign to use generated video instead of YouTube iframe
            setState(p => ({
               ...p, 
               videoUrl: generatedVideoUrl, 
               youtubeId: null, // CLEAR ID to remove iframe and avoid error 153
               videoFile: processingFile,
               progress: 60,
               statusMessage: `Translating from ${language}...`
            }));
        }

        if (!processingFile) throw new Error("No file.");

        // 4. Translate & TTS (Standard Flow)
        // If we came from YouTube, we already have the transcript/language
        let transcript = state.transcript;
        let detectedLanguage = state.detectedLanguage || "Unknown";

        if (state.inputMode === InputMode.FILE) {
             const res = await detectAndTranscribe(processingFile);
             transcript = res.transcript;
             detectedLanguage = res.language;
             setState(p => ({...p, transcript, detectedLanguage, progress: 60, statusMessage: `Translating from ${detectedLanguage}...`}));
        }

        const translated = await translateText(transcript, targetLang, detectedLanguage);
        setState(p => ({...p, translatedText: translated, progress: 80, statusMessage: "Synthesizing voice..."}));

        const audioData = await generateSpeechData(translated);
        const wavUrl = createWavUrl(audioData);
        await decodeAudio(audioData);

        // 5. Finalize
        setState(p => ({...p, progress: 100, statusMessage: "Lip-syncing...", audioUrl: wavUrl}));
        await new Promise(r => setTimeout(r, 1000));

        setState(p => ({...p, step: AppStep.RESULT, isProcessing: false, statusMessage: "Ready"}));

    } catch (e) {
        const err = e as Error;
        console.error(err);

        // Handle API Key/Permission errors specifically
        const errMsg = err.message.toLowerCase();
        if (errMsg.includes("permission denied") || 
            errMsg.includes("403") || 
            errMsg.includes("not found") ||
            errMsg.includes("authentication failed") ||
            errMsg.includes("api key")) {

             if ((window as any).aistudio) {
                 addLog("Authentication failed. Requesting new key...");
                 // Force the key selection dialog to open again
                 await (window as any).aistudio.openSelectKey();

                 setState(p => ({...p, isProcessing: false, statusMessage: "Auth Error", logs: [...p.logs, "Permission denied. Please select a valid paid API key and try again."] }));
             } else {
                 setState(p => ({...p, isProcessing: false, statusMessage: "Auth Error", logs: [...p.logs, `Permission Denied: ${err.message}`] }));
             }
        } else {
             setState(p => ({...p, isProcessing: false, statusMessage: "Failed", logs: [...p.logs, `Error: ${err.message}`] }));
        }
    }
  };

  // Playback Controls
  const handlePlayPause = async () => {
     if (isPlaying) {
         await handlePause();
     } else {
         if (audioContextRef.current?.state === 'suspended') await audioContextRef.current.resume();

         // Start Audio
         if (audioBuffer && !sourceNodeRef.current && state.step === AppStep.RESULT) {
             const src = audioContextRef.current!.createBufferSource();
             src.buffer = audioBuffer;
             src.connect(gainNodeRef.current || audioContextRef.current!.destination);
             src.start(0, currentTimeRef.current);
             src.onended = () => { if(!isSeekingRef.current) setIsPlaying(false); };
             sourceNodeRef.current = src;
         }

         videoRef.current?.play();
         if (state.youtubeId) {
             iframeRef.current?.contentWindow?.postMessage(JSON.stringify({ event: 'command', func: 'seekTo', args: [currentTimeRef.current, true] }), '*');
             iframeRef.current?.contentWindow?.postMessage(JSON.stringify({ event: 'command', func: 'playVideo' }), '*');
         }
         setIsPlaying(true);
     }
  };

  const handleSeek = (time: number) => {
      isSeekingRef.current = true;
      const t = Math.max(0, Math.min(time, duration || 100));
      currentTimeRef.current = t;
      setCurrentPlaybackTime(t);

      if (videoRef.current) videoRef.current.currentTime = t;
      if (state.youtubeId) iframeRef.current?.contentWindow?.postMessage(JSON.stringify({ event: 'command', func: 'seekTo', args: [t, true] }), '*');

      // Audio Seek
      if (sourceNodeRef.current) {
          try { sourceNodeRef.current.stop(); } catch(e){}
          sourceNodeRef.current = null;
      }
      if (isPlaying && audioBuffer && state.step === AppStep.RESULT) {
          const src = audioContextRef.current!.createBufferSource();
          src.buffer = audioBuffer;
          src.connect(gainNodeRef.current || audioContextRef.current!.destination);
          src.start(0, t);
          sourceNodeRef.current = src;
      }
      setTimeout(() => isSeekingRef.current = false, 50);
  };

  const formatTime = (s: number) => {
      const m = Math.floor(s / 60);
      const sec = Math.floor(s % 60);
      return `${m}:${sec.toString().padStart(2, '0')}`;
  };

  const handleReset = () => {
      setState(p => ({...p, step: AppStep.UPLOAD, transcript: '', translatedText: '', audioUrl: null, logs: [], progress: 0, statusMessage: "Ready", veoPrompt: null }));
      setAudioBuffer(null);
      setCurrentPlaybackTime(0);
      setIsPlaying(false);
  };

  const handleDownloadSRT = (text: string, filename: string) => {
    const srtContent = generateSRT(text);
    const blob = new Blob([srtContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="min-h-screen text-slate-100 overflow-x-hidden selection:bg-cyan-500/30">

      {/* Dynamic Background Elements */}
      <div className="fixed inset-0 pointer-events-none overflow-hidden">
        <div className="halftone w-[800px] h-[800px] rounded-full opacity-20 blur-3xl -top-40 -left-40 absolute animate-pulse"></div>
        <div className="halftone w-[600px] h-[600px] rounded-full opacity-20 blur-3xl bottom-0 -right-20 absolute"></div>
      </div>

      <header className="relative z-10 border-b border-white/5 bg-[#0b1020]/80 backdrop-blur-md sticky top-0">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-4">
             <div className="w-10 h-10 rounded-xl glass flex items-center justify-center text-cyan-300 shadow-[0_0_15px_rgba(110,231,240,0.3)]">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="currentColor"><path d="M12 3a9 9 0 1 0 9 9h-2a7 7 0 1 1-7-7V3z"/><path d="M12 7l4 4H8l4-4zm0 8v4m-4-4h8"/></svg>
             </div>
             <div>
                <h1 className="text-2xl font-bold tracking-tight bg-gradient-to-r from-cyan-200 to-violet-300 bg-clip-text text-transparent">VaniBridge</h1>
                <p className="text-xs text-slate-400 font-medium tracking-wide">AI VIDEO LOCALIZATION</p>
             </div>
          </div>
          <div className="flex items-center gap-2 px-3 py-1.5 rounded-full border border-white/10 bg-white/5 backdrop-blur-sm">
